#!/usr/bin/env tsx
/**
 * s01_agent_loop.ts - The Agent Loop
 *
 * The entire secret of an AI coding agent in one pattern:
 *
 *     while stop_reason == "tool_use":
 *         response = LLM(messages, tools)
 *         execute tools
 *         append results
 *
 *     +----------+      +-------+      +---------+
 *     |   User   | ---> |  LLM  | ---> |  Tool   |
 *     |  prompt  |      |       |      | execute |
 *     +----------+      +---+---+      +----+----+
 *                           ^               |
 *                           |   tool_result |
 *                           +---------------+
 *                           (loop continues)
 *
 * This is the core loop: feed tool results back to the model
 * until the model decides to stop. Production agents layer
 * policy, hooks, and lifecycle controls on top.
 */

import Anthropic from "@anthropic-ai/sdk";
import * as dotenv from "dotenv";
import { spawnSync } from "child_process";
import * as readline from "readline";

dotenv.config({ override: true });

const client = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
const MODEL = process.env.MODEL_ID!;
const WORKDIR = process.cwd();

const SYSTEM = `You are a coding agent at ${WORKDIR}. Use bash to solve tasks. Act, don't explain.`;

const TOOLS: Anthropic.Tool[] = [
  {
    name: "bash",
    description: "Run a shell command.",
    input_schema: {
      type: "object" as const,
      properties: { command: { type: "string" } },
      required: ["command"],
    },
  },
];

function runBash(command: string): string {
  const dangerous = ["rm -rf /", "sudo", "shutdown", "reboot", "> /dev/"];
  if (dangerous.some((d) => command.includes(d))) {
    return "Error: Dangerous command blocked";
  }
  const result = spawnSync("bash", ["-c", command], {
    cwd: WORKDIR,
    timeout: 120000,
    encoding: "utf-8",
  });
  if (result.error?.message?.includes("ETIMEDOUT")) {
    return "Error: Timeout (120s)";
  }
  const out = ((result.stdout || "") + (result.stderr || "")).trim();
  return (out || "(no output)").slice(0, 50000);
}

// -- The core pattern: a while loop that calls tools until the model stops --
async function agentLoop(messages: Anthropic.MessageParam[]): Promise<void> {
  while (true) {
    const response = await client.messages.create({
      model: MODEL,
      system: SYSTEM,
      messages,
      tools: TOOLS,
      max_tokens: 8000,
    });
    // Append assistant turn
    messages.push({ role: "assistant", content: response.content });
    // If the model didn't call a tool, we're done
    if (response.stop_reason !== "tool_use") return;
    // Execute each tool call, collect results
    const results: Anthropic.ToolResultBlockParam[] = [];
    for (const block of response.content) {
      if (block.type === "tool_use") {
        const input = block.input as { command: string };
        process.stdout.write(`\x1b[33m$ ${input.command}\x1b[0m\n`);
        const output = runBash(input.command);
        process.stdout.write(output.slice(0, 200) + "\n");
        results.push({ type: "tool_result", tool_use_id: block.id, content: output });
      }
    }
    messages.push({ role: "user", content: results });
  }
}

async function main() {
  const history: Anthropic.MessageParam[] = [];
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });

  const ask = () =>
    new Promise<string>((resolve) => rl.question("\x1b[36ms01 >> \x1b[0m", resolve));

  while (true) {
    let query: string;
    try {
      query = await ask();
    } catch {
      break;
    }
    if (["q", "exit", ""].includes(query.trim().toLowerCase())) break;
    history.push({ role: "user", content: query });
    await agentLoop(history);
    // Print final assistant response
    const last = history[history.length - 1];
    if (last.role === "assistant" && Array.isArray(last.content)) {
      for (const block of last.content) {
        if (block.type === "text") process.stdout.write(block.text + "\n");
      }
    }
    process.stdout.write("\n");
  }
  rl.close();
}

main().catch(console.error);

#!/usr/bin/env tsx
/**
 * s02_tool_use.ts - Tools
 *
 * The agent loop from s01 didn't change. We just added tools to the array
 * and a dispatch map to route calls.
 *
 *     +----------+      +-------+      +------------------+
 *     |   User   | ---> |  LLM  | ---> | Tool Dispatch    |
 *     |  prompt  |      |       |      | {                |
 *     +----------+      +---+---+      |   bash: runBash  |
 *                           ^          |   read: runRead  |
 *                           |          |   write: runWri  |
 *                           +----------+   edit: runEdit  |
 *                           tool_result| }                |
 *                                      +------------------+
 *
 * Key insight: "The loop didn't change at all. I just added tools."
 */

import Anthropic from "@anthropic-ai/sdk";
import * as dotenv from "dotenv";
import { spawnSync } from "child_process";
import * as fs from "fs";
import * as path from "path";
import * as readline from "readline";

dotenv.config({ override: true });

const client = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
const MODEL = process.env.MODEL_ID!;
const WORKDIR = process.cwd();

const SYSTEM = `You are a coding agent at ${WORKDIR}. Use tools to solve tasks. Act, don't explain.`;

function safePath(p: string): string {
  const resolved = path.resolve(WORKDIR, p);
  if (!resolved.startsWith(WORKDIR)) throw new Error(`Path escapes workspace: ${p}`);
  return resolved;
}

function runBash(command: string): string {
  const dangerous = ["rm -rf /", "sudo", "shutdown", "reboot", "> /dev/"];
  if (dangerous.some((d) => command.includes(d))) return "Error: Dangerous command blocked";
  const result = spawnSync("bash", ["-c", command], {
    cwd: WORKDIR, timeout: 120000, encoding: "utf-8",
  });
  if (result.error?.message?.includes("ETIMEDOUT")) return "Error: Timeout (120s)";
  const out = ((result.stdout || "") + (result.stderr || "")).trim();
  return (out || "(no output)").slice(0, 50000);
}

function runRead(filePath: string, limit?: number): string {
  try {
    const lines = fs.readFileSync(safePath(filePath), "utf-8").split("\n");
    const limited = (limit && limit < lines.length)
      ? [...lines.slice(0, limit), `... (${lines.length - limit} more lines)`]
      : lines;
    return limited.join("\n").slice(0, 50000);
  } catch (e) {
    return `Error: ${e}`;
  }
}

function runWrite(filePath: string, content: string): string {
  try {
    const fp = safePath(filePath);
    fs.mkdirSync(path.dirname(fp), { recursive: true });
    fs.writeFileSync(fp, content, "utf-8");
    return `Wrote ${content.length} bytes to ${filePath}`;
  } catch (e) {
    return `Error: ${e}`;
  }
}

function runEdit(filePath: string, oldText: string, newText: string): string {
  try {
    const fp = safePath(filePath);
    const content = fs.readFileSync(fp, "utf-8");
    if (!content.includes(oldText)) return `Error: Text not found in ${filePath}`;
    fs.writeFileSync(fp, content.replace(oldText, newText), "utf-8");
    return `Edited ${filePath}`;
  } catch (e) {
    return `Error: ${e}`;
  }
}

// -- The dispatch map: {tool_name: handler} --
type ToolInput = Record<string, unknown>;
const TOOL_HANDLERS: Record<string, (kw: ToolInput) => string> = {
  bash:       (kw) => runBash(kw.command as string),
  read_file:  (kw) => runRead(kw.path as string, kw.limit as number | undefined),
  write_file: (kw) => runWrite(kw.path as string, kw.content as string),
  edit_file:  (kw) => runEdit(kw.path as string, kw.old_text as string, kw.new_text as string),
};

const TOOLS: Anthropic.Tool[] = [
  { name: "bash", description: "Run a shell command.",
    input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
  { name: "read_file", description: "Read file contents.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, limit: { type: "integer" } }, required: ["path"] } },
  { name: "write_file", description: "Write content to file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, content: { type: "string" } }, required: ["path", "content"] } },
  { name: "edit_file", description: "Replace exact text in file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, old_text: { type: "string" }, new_text: { type: "string" } }, required: ["path", "old_text", "new_text"] } },
];

async function agentLoop(messages: Anthropic.MessageParam[]): Promise<void> {
  while (true) {
    const response = await client.messages.create({
      model: MODEL, system: SYSTEM, messages, tools: TOOLS, max_tokens: 8000,
    });
    messages.push({ role: "assistant", content: response.content });
    if (response.stop_reason !== "tool_use") return;
    const results: Anthropic.ToolResultBlockParam[] = [];
    for (const block of response.content) {
      if (block.type === "tool_use") {
        const handler = TOOL_HANDLERS[block.name];
        const output = handler
          ? handler(block.input as ToolInput)
          : `Unknown tool: ${block.name}`;
        process.stdout.write(`> ${block.name}: ${output.slice(0, 200)}\n`);
        results.push({ type: "tool_result", tool_use_id: block.id, content: output });
      }
    }
    messages.push({ role: "user", content: results });
  }
}

async function main() {
  const history: Anthropic.MessageParam[] = [];
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
  const ask = () => new Promise<string>((resolve) => rl.question("\x1b[36ms02 >> \x1b[0m", resolve));

  while (true) {
    let query: string;
    try { query = await ask(); } catch { break; }
    if (["q", "exit", ""].includes(query.trim().toLowerCase())) break;
    history.push({ role: "user", content: query });
    await agentLoop(history);
    const last = history[history.length - 1];
    if (last.role === "assistant" && Array.isArray(last.content)) {
      for (const block of last.content) {
        if (block.type === "text") process.stdout.write(block.text + "\n");
      }
    }
    process.stdout.write("\n");
  }
  rl.close();
}

main().catch(console.error);

#!/usr/bin/env tsx
/**
 * s03_todo_write.ts - TodoWrite
 *
 * The model tracks its own progress via a TodoManager. A nag reminder
 * forces it to keep updating when it forgets.
 *
 *     +----------+      +-------+      +---------+
 *     |   User   | ---> |  LLM  | ---> | Tools   |
 *     |  prompt  |      |       |      | + todo  |
 *     +----------+      +---+---+      +----+----+
 *                           ^               |
 *                           |   tool_result |
 *                           +---------------+
 *                                 |
 *                     +-----------+-----------+
 *                     | TodoManager state     |
 *                     | [ ] task A            |
 *                     | [>] task B <- doing   |
 *                     | [x] task C            |
 *                     +-----------------------+
 *                                 |
 *                     if rounds_since_todo >= 3:
 *                       inject <reminder>
 *
 * Key insight: "The agent can track its own progress -- and I can see it."
 */

import Anthropic from "@anthropic-ai/sdk";
import * as dotenv from "dotenv";
import { spawnSync } from "child_process";
import * as fs from "fs";
import * as path from "path";
import * as readline from "readline";

dotenv.config({ override: true });

const client = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
const MODEL = process.env.MODEL_ID!;
const WORKDIR = process.cwd();

const SYSTEM = `You are a coding agent at ${WORKDIR}.
Use the todo tool to plan multi-step tasks. Mark in_progress before starting, completed when done.
Prefer tools over prose.`;

// -- TodoManager: structured state the LLM writes to --
interface TodoItem {
  id: string;
  text: string;
  status: "pending" | "in_progress" | "completed";
}

class TodoManager {
  private items: TodoItem[] = [];

  update(items: Array<{ id?: string; text?: string; status?: string }>): string {
    if (items.length > 20) throw new Error("Max 20 todos allowed");
    const validated: TodoItem[] = [];
    let inProgressCount = 0;
    for (let i = 0; i < items.length; i++) {
      const item = items[i];
      const text = String(item.text || "").trim();
      const status = String(item.status || "pending").toLowerCase() as TodoItem["status"];
      const id = String(item.id || String(i + 1));
      if (!text) throw new Error(`Item ${id}: text required`);
      if (!["pending", "in_progress", "completed"].includes(status))
        throw new Error(`Item ${id}: invalid status '${status}'`);
      if (status === "in_progress") inProgressCount++;
      validated.push({ id, text, status });
    }
    if (inProgressCount > 1) throw new Error("Only one task can be in_progress at a time");
    this.items = validated;
    return this.render();
  }

  render(): string {
    if (!this.items.length) return "No todos.";
    const markers: Record<string, string> = { pending: "[ ]", in_progress: "[>]", completed: "[x]" };
    const lines = this.items.map((item) => `${markers[item.status]} #${item.id}: ${item.text}`);
    const done = this.items.filter((t) => t.status === "completed").length;
    lines.push(`\n(${done}/${this.items.length} completed)`);
    return lines.join("\n");
  }
}

const TODO = new TodoManager();

type ToolInput = Record<string, unknown>;

function safePath(p: string): string {
  const resolved = path.resolve(WORKDIR, p);
  if (!resolved.startsWith(WORKDIR)) throw new Error(`Path escapes workspace: ${p}`);
  return resolved;
}

function runBash(command: string): string {
  const dangerous = ["rm -rf /", "sudo", "shutdown", "reboot", "> /dev/"];
  if (dangerous.some((d) => command.includes(d))) return "Error: Dangerous command blocked";
  const result = spawnSync("bash", ["-c", command], { cwd: WORKDIR, timeout: 120000, encoding: "utf-8" });
  if (result.error?.message?.includes("ETIMEDOUT")) return "Error: Timeout (120s)";
  const out = ((result.stdout || "") + (result.stderr || "")).trim();
  return (out || "(no output)").slice(0, 50000);
}

function runRead(filePath: string, limit?: number): string {
  try {
    const lines = fs.readFileSync(safePath(filePath), "utf-8").split("\n");
    const limited = (limit && limit < lines.length)
      ? [...lines.slice(0, limit), `... (${lines.length - limit} more)`]
      : lines;
    return limited.join("\n").slice(0, 50000);
  } catch (e) { return `Error: ${e}`; }
}

function runWrite(filePath: string, content: string): string {
  try {
    const fp = safePath(filePath);
    fs.mkdirSync(path.dirname(fp), { recursive: true });
    fs.writeFileSync(fp, content, "utf-8");
    return `Wrote ${content.length} bytes`;
  } catch (e) { return `Error: ${e}`; }
}

function runEdit(filePath: string, oldText: string, newText: string): string {
  try {
    const fp = safePath(filePath);
    const content = fs.readFileSync(fp, "utf-8");
    if (!content.includes(oldText)) return `Error: Text not found in ${filePath}`;
    fs.writeFileSync(fp, content.replace(oldText, newText), "utf-8");
    return `Edited ${filePath}`;
  } catch (e) { return `Error: ${e}`; }
}

const TOOL_HANDLERS: Record<string, (kw: ToolInput) => string> = {
  bash:       (kw) => runBash(kw.command as string),
  read_file:  (kw) => runRead(kw.path as string, kw.limit as number | undefined),
  write_file: (kw) => runWrite(kw.path as string, kw.content as string),
  edit_file:  (kw) => runEdit(kw.path as string, kw.old_text as string, kw.new_text as string),
  todo:       (kw) => TODO.update(kw.items as Array<{ id?: string; text?: string; status?: string }>),
};

const TOOLS: Anthropic.Tool[] = [
  { name: "bash", description: "Run a shell command.",
    input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
  { name: "read_file", description: "Read file contents.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, limit: { type: "integer" } }, required: ["path"] } },
  { name: "write_file", description: "Write content to file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, content: { type: "string" } }, required: ["path", "content"] } },
  { name: "edit_file", description: "Replace exact text in file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, old_text: { type: "string" }, new_text: { type: "string" } }, required: ["path", "old_text", "new_text"] } },
  { name: "todo", description: "Update task list. Track progress on multi-step tasks.",
    input_schema: { type: "object" as const, properties: { items: { type: "array", items: { type: "object", properties: { id: { type: "string" }, text: { type: "string" }, status: { type: "string", enum: ["pending", "in_progress", "completed"] } }, required: ["id", "text", "status"] } } }, required: ["items"] } },
];

// -- Agent loop with nag reminder injection --
async function agentLoop(messages: Anthropic.MessageParam[]): Promise<void> {
  let roundsSinceTodo = 0;
  while (true) {
    const response = await client.messages.create({
      model: MODEL, system: SYSTEM, messages, tools: TOOLS, max_tokens: 8000,
    });
    messages.push({ role: "assistant", content: response.content });
    if (response.stop_reason !== "tool_use") return;
    const results: Array<Anthropic.ToolResultBlockParam | { type: "text"; text: string }> = [];
    let usedTodo = false;
    for (const block of response.content) {
      if (block.type === "tool_use") {
        const handler = TOOL_HANDLERS[block.name];
        let output: string;
        try {
          output = handler ? handler(block.input as ToolInput) : `Unknown tool: ${block.name}`;
        } catch (e) {
          output = `Error: ${e}`;
        }
        process.stdout.write(`> ${block.name}: ${String(output).slice(0, 200)}\n`);
        results.push({ type: "tool_result", tool_use_id: block.id, content: String(output) });
        if (block.name === "todo") usedTodo = true;
      }
    }
    roundsSinceTodo = usedTodo ? 0 : roundsSinceTodo + 1;
    if (roundsSinceTodo >= 3) {
      results.unshift({ type: "text", text: "<reminder>Update your todos.</reminder>" });
    }
    messages.push({ role: "user", content: results as Anthropic.MessageParam["content"] });
  }
}

async function main() {
  const history: Anthropic.MessageParam[] = [];
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
  const ask = () => new Promise<string>((resolve) => rl.question("\x1b[36ms03 >> \x1b[0m", resolve));

  while (true) {
    let query: string;
    try { query = await ask(); } catch { break; }
    if (["q", "exit", ""].includes(query.trim().toLowerCase())) break;
    history.push({ role: "user", content: query });
    await agentLoop(history);
    const last = history[history.length - 1];
    if (last.role === "assistant" && Array.isArray(last.content)) {
      for (const block of last.content) {
        if (block.type === "text") process.stdout.write(block.text + "\n");
      }
    }
    process.stdout.write("\n");
  }
  rl.close();
}

main().catch(console.error);

#!/usr/bin/env tsx
/**
 * s04_subagent.ts - Subagents
 *
 * Spawn a child agent with fresh messages=[]. The child works in its own
 * context, sharing the filesystem, then returns only a summary to the parent.
 *
 *     Parent agent                     Subagent
 *     +------------------+             +------------------+
 *     | messages=[...]   |             | messages=[]      |  <-- fresh
 *     |                  |  dispatch   |                  |
 *     | tool: task       | ---------->| while tool_use:  |
 *     |   prompt="..."   |            |   call tools     |
 *     |   description="" |            |   append results |
 *     |                  |  summary   |                  |
 *     |   result = "..." | <--------- | return last text |
 *     +------------------+             +------------------+
 *               |
 *     Parent context stays clean.
 *     Subagent context is discarded.
 *
 * Key insight: "Process isolation gives context isolation for free."
 */

import Anthropic from "@anthropic-ai/sdk";
import * as dotenv from "dotenv";
import { spawnSync } from "child_process";
import * as fs from "fs";
import * as path from "path";
import * as readline from "readline";

dotenv.config({ override: true });

const client = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
const MODEL = process.env.MODEL_ID!;
const WORKDIR = process.cwd();

const SYSTEM = `You are a coding agent at ${WORKDIR}. Use the task tool to delegate exploration or subtasks.`;
const SUBAGENT_SYSTEM = `You are a coding subagent at ${WORKDIR}. Complete the given task, then summarize your findings.`;

type ToolInput = Record<string, unknown>;

function safePath(p: string): string {
  const resolved = path.resolve(WORKDIR, p);
  if (!resolved.startsWith(WORKDIR)) throw new Error(`Path escapes workspace: ${p}`);
  return resolved;
}

function runBash(command: string): string {
  const dangerous = ["rm -rf /", "sudo", "shutdown", "reboot", "> /dev/"];
  if (dangerous.some((d) => command.includes(d))) return "Error: Dangerous command blocked";
  const result = spawnSync("bash", ["-c", command], { cwd: WORKDIR, timeout: 120000, encoding: "utf-8" });
  if (result.error?.message?.includes("ETIMEDOUT")) return "Error: Timeout (120s)";
  const out = ((result.stdout || "") + (result.stderr || "")).trim();
  return (out || "(no output)").slice(0, 50000);
}

function runRead(filePath: string, limit?: number): string {
  try {
    const lines = fs.readFileSync(safePath(filePath), "utf-8").split("\n");
    const limited = (limit && limit < lines.length)
      ? [...lines.slice(0, limit), `... (${lines.length - limit} more)`]
      : lines;
    return limited.join("\n").slice(0, 50000);
  } catch (e) { return `Error: ${e}`; }
}

function runWrite(filePath: string, content: string): string {
  try {
    const fp = safePath(filePath);
    fs.mkdirSync(path.dirname(fp), { recursive: true });
    fs.writeFileSync(fp, content, "utf-8");
    return `Wrote ${content.length} bytes`;
  } catch (e) { return `Error: ${e}`; }
}

function runEdit(filePath: string, oldText: string, newText: string): string {
  try {
    const fp = safePath(filePath);
    const content = fs.readFileSync(fp, "utf-8");
    if (!content.includes(oldText)) return `Error: Text not found in ${filePath}`;
    fs.writeFileSync(fp, content.replace(oldText, newText), "utf-8");
    return `Edited ${filePath}`;
  } catch (e) { return `Error: ${e}`; }
}

const TOOL_HANDLERS: Record<string, (kw: ToolInput) => string> = {
  bash:       (kw) => runBash(kw.command as string),
  read_file:  (kw) => runRead(kw.path as string, kw.limit as number | undefined),
  write_file: (kw) => runWrite(kw.path as string, kw.content as string),
  edit_file:  (kw) => runEdit(kw.path as string, kw.old_text as string, kw.new_text as string),
};

// Child gets all base tools except task (no recursive spawning)
const CHILD_TOOLS: Anthropic.Tool[] = [
  { name: "bash", description: "Run a shell command.",
    input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
  { name: "read_file", description: "Read file contents.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, limit: { type: "integer" } }, required: ["path"] } },
  { name: "write_file", description: "Write content to file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, content: { type: "string" } }, required: ["path", "content"] } },
  { name: "edit_file", description: "Replace exact text in file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, old_text: { type: "string" }, new_text: { type: "string" } }, required: ["path", "old_text", "new_text"] } },
];

// -- Subagent: fresh context, filtered tools, summary-only return --
async function runSubagent(prompt: string): Promise<string> {
  const subMessages: Anthropic.MessageParam[] = [{ role: "user", content: prompt }]; // fresh context
  let response: Anthropic.Message | null = null;
  for (let i = 0; i < 30; i++) { // safety limit
    response = await client.messages.create({
      model: MODEL, system: SUBAGENT_SYSTEM, messages: subMessages,
      tools: CHILD_TOOLS, max_tokens: 8000,
    });
    subMessages.push({ role: "assistant", content: response.content });
    if (response.stop_reason !== "tool_use") break;
    const results: Anthropic.ToolResultBlockParam[] = [];
    for (const block of response.content) {
      if (block.type === "tool_use") {
        const handler = TOOL_HANDLERS[block.name];
        const output = handler ? handler(block.input as ToolInput) : `Unknown tool: ${block.name}`;
        results.push({ type: "tool_result", tool_use_id: block.id, content: String(output).slice(0, 50000) });
      }
    }
    subMessages.push({ role: "user", content: results });
  }
  // Only the final text returns to the parent -- child context is discarded
  if (!response) return "(no summary)";
  return response.content
    .filter((b): b is Anthropic.TextBlock => b.type === "text")
    .map((b) => b.text)
    .join("") || "(no summary)";
}

// -- Parent tools: base tools + task dispatcher --
const PARENT_TOOLS: Anthropic.Tool[] = [
  ...CHILD_TOOLS,
  { name: "task", description: "Spawn a subagent with fresh context. It shares the filesystem but not conversation history.",
    input_schema: { type: "object" as const, properties: { prompt: { type: "string" }, description: { type: "string", description: "Short description of the task" } }, required: ["prompt"] } },
];

async function agentLoop(messages: Anthropic.MessageParam[]): Promise<void> {
  while (true) {
    const response = await client.messages.create({
      model: MODEL, system: SYSTEM, messages, tools: PARENT_TOOLS, max_tokens: 8000,
    });
    messages.push({ role: "assistant", content: response.content });
    if (response.stop_reason !== "tool_use") return;
    const results: Anthropic.ToolResultBlockParam[] = [];
    for (const block of response.content) {
      if (block.type === "tool_use") {
        let output: string;
        if (block.name === "task") {
          const input = block.input as { prompt: string; description?: string };
          const desc = input.description || "subtask";
          process.stdout.write(`> task (${desc}): ${input.prompt.slice(0, 80)}\n`);
          output = await runSubagent(input.prompt);
        } else {
          const handler = TOOL_HANDLERS[block.name];
          output = handler ? handler(block.input as ToolInput) : `Unknown tool: ${block.name}`;
        }
        process.stdout.write(`  ${String(output).slice(0, 200)}\n`);
        results.push({ type: "tool_result", tool_use_id: block.id, content: String(output) });
      }
    }
    messages.push({ role: "user", content: results });
  }
}

async function main() {
  const history: Anthropic.MessageParam[] = [];
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
  const ask = () => new Promise<string>((resolve) => rl.question("\x1b[36ms04 >> \x1b[0m", resolve));

  while (true) {
    let query: string;
    try { query = await ask(); } catch { break; }
    if (["q", "exit", ""].includes(query.trim().toLowerCase())) break;
    history.push({ role: "user", content: query });
    await agentLoop(history);
    const last = history[history.length - 1];
    if (last.role === "assistant" && Array.isArray(last.content)) {
      for (const block of last.content) {
        if (block.type === "text") process.stdout.write(block.text + "\n");
      }
    }
    process.stdout.write("\n");
  }
  rl.close();
}

main().catch(console.error);

#!/usr/bin/env tsx
/**
 * s05_skill_loading.ts - Skills
 *
 * Two-layer skill injection that avoids bloating the system prompt:
 *
 *     Layer 1 (cheap): skill names in system prompt (~100 tokens/skill)
 *     Layer 2 (on demand): full skill body in tool_result
 *
 *     skills/
 *       pdf/
 *         SKILL.md          <-- frontmatter (name, description) + body
 *       code-review/
 *         SKILL.md
 *
 *     System prompt:
 *     +--------------------------------------+
 *     | You are a coding agent.              |
 *     | Skills available:                    |
 *     |   - pdf: Process PDF files...        |  <-- Layer 1: metadata only
 *     |   - code-review: Review code...      |
 *     +--------------------------------------+
 *
 *     When model calls load_skill("pdf"):
 *     +--------------------------------------+
 *     | tool_result:                         |
 *     | <skill>                              |
 *     |   Full PDF processing instructions   |  <-- Layer 2: full body
 *     |   Step 1: ...                        |
 *     |   Step 2: ...                        |
 *     | </skill>                             |
 *     +--------------------------------------+
 *
 * Key insight: "Don't put everything in the system prompt. Load on demand."
 */

import Anthropic from "@anthropic-ai/sdk";
import * as dotenv from "dotenv";
import { spawnSync } from "child_process";
import * as fs from "fs";
import * as path from "path";
import * as readline from "readline";

dotenv.config({ override: true });

const client = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
const MODEL = process.env.MODEL_ID!;
const WORKDIR = process.cwd();
const SKILLS_DIR = path.join(WORKDIR, "skills");

// -- SkillLoader: scan skills/<name>/SKILL.md with YAML frontmatter --
interface SkillEntry {
  meta: Record<string, string>;
  body: string;
  filePath: string;
}

class SkillLoader {
  private skills: Map<string, SkillEntry> = new Map();

  constructor(skillsDir: string) {
    this.loadAll(skillsDir);
  }

  private loadAll(skillsDir: string) {
    if (!fs.existsSync(skillsDir)) return;
    this.findSkillFiles(skillsDir).sort().forEach((f) => {
      const text = fs.readFileSync(f, "utf-8");
      const { meta, body } = this.parseFrontmatter(text);
      const name = meta.name || path.basename(path.dirname(f));
      this.skills.set(name, { meta, body, filePath: f });
    });
  }

  private findSkillFiles(dir: string): string[] {
    const results: string[] = [];
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        results.push(...this.findSkillFiles(fullPath));
      } else if (entry.name === "SKILL.md") {
        results.push(fullPath);
      }
    }
    return results;
  }

  private parseFrontmatter(text: string): { meta: Record<string, string>; body: string } {
    const match = text.match(/^---\n(.*?)\n---\n(.*)/s);
    if (!match) return { meta: {}, body: text };
    const meta: Record<string, string> = {};
    for (const line of match[1].trim().split("\n")) {
      const colonIdx = line.indexOf(":");
      if (colonIdx !== -1) {
        meta[line.slice(0, colonIdx).trim()] = line.slice(colonIdx + 1).trim();
      }
    }
    return { meta, body: match[2].trim() };
  }

  getDescriptions(): string {
    if (!this.skills.size) return "(no skills available)";
    const lines: string[] = [];
    for (const [name, skill] of this.skills) {
      const desc = skill.meta.description || "No description";
      const tags = skill.meta.tags || "";
      let line = `  - ${name}: ${desc}`;
      if (tags) line += ` [${tags}]`;
      lines.push(line);
    }
    return lines.join("\n");
  }

  getContent(name: string): string {
    const skill = this.skills.get(name);
    if (!skill) {
      return `Error: Unknown skill '${name}'. Available: ${[...this.skills.keys()].join(", ")}`;
    }
    return `<skill name="${name}">\n${skill.body}\n</skill>`;
  }
}

const SKILL_LOADER = new SkillLoader(SKILLS_DIR);

// Layer 1: skill metadata injected into system prompt
const SYSTEM = `You are a coding agent at ${WORKDIR}.
Use load_skill to access specialized knowledge before tackling unfamiliar topics.

Skills available:
${SKILL_LOADER.getDescriptions()}`;

type ToolInput = Record<string, unknown>;

function safePath(p: string): string {
  const resolved = path.resolve(WORKDIR, p);
  if (!resolved.startsWith(WORKDIR)) throw new Error(`Path escapes workspace: ${p}`);
  return resolved;
}

function runBash(command: string): string {
  const dangerous = ["rm -rf /", "sudo", "shutdown", "reboot", "> /dev/"];
  if (dangerous.some((d) => command.includes(d))) return "Error: Dangerous command blocked";
  const result = spawnSync("bash", ["-c", command], { cwd: WORKDIR, timeout: 120000, encoding: "utf-8" });
  if (result.error?.message?.includes("ETIMEDOUT")) return "Error: Timeout (120s)";
  const out = ((result.stdout || "") + (result.stderr || "")).trim();
  return (out || "(no output)").slice(0, 50000);
}

function runRead(filePath: string, limit?: number): string {
  try {
    const lines = fs.readFileSync(safePath(filePath), "utf-8").split("\n");
    const limited = (limit && limit < lines.length)
      ? [...lines.slice(0, limit), `... (${lines.length - limit} more)`]
      : lines;
    return limited.join("\n").slice(0, 50000);
  } catch (e) { return `Error: ${e}`; }
}

function runWrite(filePath: string, content: string): string {
  try {
    const fp = safePath(filePath);
    fs.mkdirSync(path.dirname(fp), { recursive: true });
    fs.writeFileSync(fp, content, "utf-8");
    return `Wrote ${content.length} bytes`;
  } catch (e) { return `Error: ${e}`; }
}

function runEdit(filePath: string, oldText: string, newText: string): string {
  try {
    const fp = safePath(filePath);
    const content = fs.readFileSync(fp, "utf-8");
    if (!content.includes(oldText)) return `Error: Text not found in ${filePath}`;
    fs.writeFileSync(fp, content.replace(oldText, newText), "utf-8");
    return `Edited ${filePath}`;
  } catch (e) { return `Error: ${e}`; }
}

const TOOL_HANDLERS: Record<string, (kw: ToolInput) => string> = {
  bash:       (kw) => runBash(kw.command as string),
  read_file:  (kw) => runRead(kw.path as string, kw.limit as number | undefined),
  write_file: (kw) => runWrite(kw.path as string, kw.content as string),
  edit_file:  (kw) => runEdit(kw.path as string, kw.old_text as string, kw.new_text as string),
  load_skill: (kw) => SKILL_LOADER.getContent(kw.name as string),
};

const TOOLS: Anthropic.Tool[] = [
  { name: "bash", description: "Run a shell command.",
    input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
  { name: "read_file", description: "Read file contents.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, limit: { type: "integer" } }, required: ["path"] } },
  { name: "write_file", description: "Write content to file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, content: { type: "string" } }, required: ["path", "content"] } },
  { name: "edit_file", description: "Replace exact text in file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, old_text: { type: "string" }, new_text: { type: "string" } }, required: ["path", "old_text", "new_text"] } },
  { name: "load_skill", description: "Load specialized knowledge by name.",
    input_schema: { type: "object" as const, properties: { name: { type: "string", description: "Skill name to load" } }, required: ["name"] } },
];

async function agentLoop(messages: Anthropic.MessageParam[]): Promise<void> {
  while (true) {
    const response = await client.messages.create({
      model: MODEL, system: SYSTEM, messages, tools: TOOLS, max_tokens: 8000,
    });
    messages.push({ role: "assistant", content: response.content });
    if (response.stop_reason !== "tool_use") return;
    const results: Anthropic.ToolResultBlockParam[] = [];
    for (const block of response.content) {
      if (block.type === "tool_use") {
        const handler = TOOL_HANDLERS[block.name];
        let output: string;
        try {
          output = handler ? handler(block.input as ToolInput) : `Unknown tool: ${block.name}`;
        } catch (e) {
          output = `Error: ${e}`;
        }
        process.stdout.write(`> ${block.name}: ${String(output).slice(0, 200)}\n`);
        results.push({ type: "tool_result", tool_use_id: block.id, content: String(output) });
      }
    }
    messages.push({ role: "user", content: results });
  }
}

async function main() {
  const history: Anthropic.MessageParam[] = [];
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
  const ask = () => new Promise<string>((resolve) => rl.question("\x1b[36ms05 >> \x1b[0m", resolve));

  while (true) {
    let query: string;
    try { query = await ask(); } catch { break; }
    if (["q", "exit", ""].includes(query.trim().toLowerCase())) break;
    history.push({ role: "user", content: query });
    await agentLoop(history);
    const last = history[history.length - 1];
    if (last.role === "assistant" && Array.isArray(last.content)) {
      for (const block of last.content) {
        if (block.type === "text") process.stdout.write(block.text + "\n");
      }
    }
    process.stdout.write("\n");
  }
  rl.close();
}

main().catch(console.error);

#!/usr/bin/env tsx
/**
 * s06_context_compact.ts - Compact
 *
 * Three-layer compression pipeline so the agent can work forever:
 *
 *     Every turn:
 *     +------------------+
 *     | Tool call result |
 *     +------------------+
 *             |
 *             v
 *     [Layer 1: microCompact]        (silent, every turn)
 *       Replace tool_result content older than last 3
 *       with "[Previous: used {tool_name}]"
 *             |
 *             v
 *     [Check: tokens > 50000?]
 *        |               |
 *        no              yes
 *        |               |
 *        v               v
 *     continue    [Layer 2: autoCompact]
 *                   Save full transcript to .transcripts/
 *                   Ask LLM to summarize conversation.
 *                   Replace all messages with [summary].
 *                         |
 *                         v
 *                 [Layer 3: compact tool]
 *                   Model calls compact -> immediate summarization.
 *                   Same as auto, triggered manually.
 *
 * Key insight: "The agent can forget strategically and keep working forever."
 */

import Anthropic from "@anthropic-ai/sdk";
import * as dotenv from "dotenv";
import { spawnSync } from "child_process";
import * as fs from "fs";
import * as path from "path";
import * as readline from "readline";

dotenv.config({ override: true });

const client = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
const MODEL = process.env.MODEL_ID!;
const WORKDIR = process.cwd();

const SYSTEM = `You are a coding agent at ${WORKDIR}. Use tools to solve tasks.`;

const THRESHOLD = 50000;
const TRANSCRIPT_DIR = path.join(WORKDIR, ".transcripts");
const KEEP_RECENT = 3;

function estimateTokens(messages: Anthropic.MessageParam[]): number {
  return JSON.stringify(messages).length / 4;
}

// -- Layer 1: microCompact - replace old tool results with placeholders --
function microCompact(messages: Anthropic.MessageParam[]): void {
  const toolResults: Array<{ msg: Anthropic.MessageParam; part: Record<string, unknown> }> = [];

  for (const msg of messages) {
    if (msg.role === "user" && Array.isArray(msg.content)) {
      for (const part of msg.content) {
        if (typeof part === "object" && part !== null && (part as Record<string, unknown>).type === "tool_result") {
          toolResults.push({ msg, part: part as Record<string, unknown> });
        }
      }
    }
  }

  if (toolResults.length <= KEEP_RECENT) return;

  // Build tool name map from assistant messages
  const toolNameMap: Map<string, string> = new Map();
  for (const msg of messages) {
    if (msg.role === "assistant" && Array.isArray(msg.content)) {
      for (const block of msg.content) {
        if (typeof block === "object" && block !== null && block.type === "tool_use") {
          const b = block as Anthropic.ToolUseBlock;
          toolNameMap.set(b.id, b.name);
        }
      }
    }
  }

  const toClean = toolResults.slice(0, toolResults.length - KEEP_RECENT);
  for (const { part } of toClean) {
    if (typeof part.content === "string" && part.content.length > 100) {
      const toolId = String(part.tool_use_id || "");
      const toolName = toolNameMap.get(toolId) || "unknown";
      part.content = `[Previous: used ${toolName}]`;
    }
  }
}

// -- Layer 2: autoCompact - save transcript, summarize, replace messages --
async function autoCompact(messages: Anthropic.MessageParam[]): Promise<Anthropic.MessageParam[]> {
  fs.mkdirSync(TRANSCRIPT_DIR, { recursive: true });
  const transcriptPath = path.join(TRANSCRIPT_DIR, `transcript_${Date.now()}.jsonl`);
  const lines = messages.map((m) => JSON.stringify(m)).join("\n");
  fs.writeFileSync(transcriptPath, lines, "utf-8");
  process.stdout.write(`[transcript saved: ${transcriptPath}]\n`);

  const conversationText = JSON.stringify(messages).slice(0, 80000);
  const response = await client.messages.create({
    model: MODEL,
    messages: [{ role: "user", content:
      "Summarize this conversation for continuity. Include: " +
      "1) What was accomplished, 2) Current state, 3) Key decisions made. " +
      "Be concise but preserve critical details.\n\n" + conversationText }],
    max_tokens: 2000,
  });
  const summary = (response.content[0] as Anthropic.TextBlock).text;
  return [
    { role: "user", content: `[Conversation compressed. Transcript: ${transcriptPath}]\n\n${summary}` },
    { role: "assistant", content: "Understood. I have the context from the summary. Continuing." },
  ];
}

type ToolInput = Record<string, unknown>;

function safePath(p: string): string {
  const resolved = path.resolve(WORKDIR, p);
  if (!resolved.startsWith(WORKDIR)) throw new Error(`Path escapes workspace: ${p}`);
  return resolved;
}

function runBash(command: string): string {
  const dangerous = ["rm -rf /", "sudo", "shutdown", "reboot", "> /dev/"];
  if (dangerous.some((d) => command.includes(d))) return "Error: Dangerous command blocked";
  const result = spawnSync("bash", ["-c", command], { cwd: WORKDIR, timeout: 120000, encoding: "utf-8" });
  if (result.error?.message?.includes("ETIMEDOUT")) return "Error: Timeout (120s)";
  const out = ((result.stdout || "") + (result.stderr || "")).trim();
  return (out || "(no output)").slice(0, 50000);
}

function runRead(filePath: string, limit?: number): string {
  try {
    const lines = fs.readFileSync(safePath(filePath), "utf-8").split("\n");
    const limited = (limit && limit < lines.length)
      ? [...lines.slice(0, limit), `... (${lines.length - limit} more)`]
      : lines;
    return limited.join("\n").slice(0, 50000);
  } catch (e) { return `Error: ${e}`; }
}

function runWrite(filePath: string, content: string): string {
  try {
    const fp = safePath(filePath);
    fs.mkdirSync(path.dirname(fp), { recursive: true });
    fs.writeFileSync(fp, content, "utf-8");
    return `Wrote ${content.length} bytes`;
  } catch (e) { return `Error: ${e}`; }
}

function runEdit(filePath: string, oldText: string, newText: string): string {
  try {
    const fp = safePath(filePath);
    const content = fs.readFileSync(fp, "utf-8");
    if (!content.includes(oldText)) return `Error: Text not found in ${filePath}`;
    fs.writeFileSync(fp, content.replace(oldText, newText), "utf-8");
    return `Edited ${filePath}`;
  } catch (e) { return `Error: ${e}`; }
}

const TOOL_HANDLERS: Record<string, (kw: ToolInput) => string> = {
  bash:      (kw) => runBash(kw.command as string),
  read_file: (kw) => runRead(kw.path as string, kw.limit as number | undefined),
  write_file:(kw) => runWrite(kw.path as string, kw.content as string),
  edit_file: (kw) => runEdit(kw.path as string, kw.old_text as string, kw.new_text as string),
  compact:   () => "Manual compression requested.",
};

const TOOLS: Anthropic.Tool[] = [
  { name: "bash", description: "Run a shell command.",
    input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
  { name: "read_file", description: "Read file contents.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, limit: { type: "integer" } }, required: ["path"] } },
  { name: "write_file", description: "Write content to file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, content: { type: "string" } }, required: ["path", "content"] } },
  { name: "edit_file", description: "Replace exact text in file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, old_text: { type: "string" }, new_text: { type: "string" } }, required: ["path", "old_text", "new_text"] } },
  { name: "compact", description: "Trigger manual conversation compression.",
    input_schema: { type: "object" as const, properties: { focus: { type: "string", description: "What to preserve in the summary" } } } },
];

async function agentLoop(messages: Anthropic.MessageParam[]): Promise<void> {
  while (true) {
    // Layer 1: microCompact before each LLM call
    microCompact(messages);
    // Layer 2: autoCompact if token estimate exceeds threshold
    if (estimateTokens(messages) > THRESHOLD) {
      process.stdout.write("[auto_compact triggered]\n");
      const compacted = await autoCompact(messages);
      messages.splice(0, messages.length, ...compacted);
    }
    const response = await client.messages.create({
      model: MODEL, system: SYSTEM, messages, tools: TOOLS, max_tokens: 8000,
    });
    messages.push({ role: "assistant", content: response.content });
    if (response.stop_reason !== "tool_use") return;
    const results: Anthropic.ToolResultBlockParam[] = [];
    let manualCompact = false;
    for (const block of response.content) {
      if (block.type === "tool_use") {
        if (block.name === "compact") {
          manualCompact = true;
        }
        const handler = TOOL_HANDLERS[block.name];
        let output: string;
        try {
          output = handler ? handler(block.input as ToolInput) : `Unknown tool: ${block.name}`;
        } catch (e) {
          output = `Error: ${e}`;
        }
        process.stdout.write(`> ${block.name}: ${String(output).slice(0, 200)}\n`);
        results.push({ type: "tool_result", tool_use_id: block.id, content: String(output) });
      }
    }
    messages.push({ role: "user", content: results });
    // Layer 3: manual compact triggered by the compact tool
    if (manualCompact) {
      process.stdout.write("[manual compact]\n");
      const compacted = await autoCompact(messages);
      messages.splice(0, messages.length, ...compacted);
    }
  }
}

async function main() {
  const history: Anthropic.MessageParam[] = [];
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
  const ask = () => new Promise<string>((resolve) => rl.question("\x1b[36ms06 >> \x1b[0m", resolve));

  while (true) {
    let query: string;
    try { query = await ask(); } catch { break; }
    if (["q", "exit", ""].includes(query.trim().toLowerCase())) break;
    history.push({ role: "user", content: query });
    await agentLoop(history);
    const last = history[history.length - 1];
    if (last.role === "assistant" && Array.isArray(last.content)) {
      for (const block of last.content) {
        if (block.type === "text") process.stdout.write(block.text + "\n");
      }
    }
    process.stdout.write("\n");
  }
  rl.close();
}

main().catch(console.error);

#!/usr/bin/env tsx
/**
 * s07_task_system.ts - Tasks
 *
 * Tasks persist as JSON files in .tasks/ so they survive context compression.
 * Each task has a dependency graph (blockedBy/blocks).
 *
 *     .tasks/
 *       task_1.json  {"id":1, "subject":"...", "status":"completed", ...}
 *       task_2.json  {"id":2, "blockedBy":[1], "status":"pending", ...}
 *       task_3.json  {"id":3, "blockedBy":[2], "blocks":[], ...}
 *
 *     Dependency resolution:
 *     +----------+     +----------+     +----------+
 *     | task 1   | --> | task 2   | --> | task 3   |
 *     | complete |     | blocked  |     | blocked  |
 *     +----------+     +----------+     +----------+
 *          |                ^
 *          +--- completing task 1 removes it from task 2's blockedBy
 *
 * Key insight: "State that survives compression -- because it's outside the conversation."
 */

import Anthropic from "@anthropic-ai/sdk";
import * as dotenv from "dotenv";
import { spawnSync } from "child_process";
import * as fs from "fs";
import * as path from "path";
import * as readline from "readline";

dotenv.config({ override: true });

const client = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
const MODEL = process.env.MODEL_ID!;
const WORKDIR = process.cwd();
const TASKS_DIR = path.join(WORKDIR, ".tasks");

const SYSTEM = `You are a coding agent at ${WORKDIR}. Use task tools to plan and track work.`;

interface Task {
  id: number;
  subject: string;
  description: string;
  status: "pending" | "in_progress" | "completed";
  blockedBy: number[];
  blocks: number[];
  owner: string;
}

// -- TaskManager: CRUD with dependency graph, persisted as JSON files --
class TaskManager {
  private nextId: number;

  constructor(private tasksDir: string) {
    fs.mkdirSync(tasksDir, { recursive: true });
    this.nextId = this.maxId() + 1;
  }

  private maxId(): number {
    const files = fs.readdirSync(this.tasksDir).filter((f) => /^task_\d+\.json$/.test(f));
    if (!files.length) return 0;
    return Math.max(...files.map((f) => parseInt(f.split("_")[1])));
  }

  private taskPath(id: number): string {
    return path.join(this.tasksDir, `task_${id}.json`);
  }

  private load(id: number): Task {
    const p = this.taskPath(id);
    if (!fs.existsSync(p)) throw new Error(`Task ${id} not found`);
    return JSON.parse(fs.readFileSync(p, "utf-8")) as Task;
  }

  private save(task: Task): void {
    fs.writeFileSync(this.taskPath(task.id), JSON.stringify(task, null, 2), "utf-8");
  }

  create(subject: string, description = ""): string {
    const task: Task = {
      id: this.nextId, subject, description,
      status: "pending", blockedBy: [], blocks: [], owner: "",
    };
    this.save(task);
    this.nextId++;
    return JSON.stringify(task, null, 2);
  }

  get(id: number): string {
    return JSON.stringify(this.load(id), null, 2);
  }

  update(id: number, status?: string, addBlockedBy?: number[], addBlocks?: number[]): string {
    const task = this.load(id);
    if (status) {
      if (!["pending", "in_progress", "completed"].includes(status))
        throw new Error(`Invalid status: ${status}`);
      task.status = status as Task["status"];
      if (status === "completed") this.clearDependency(id);
    }
    if (addBlockedBy) {
      task.blockedBy = [...new Set([...task.blockedBy, ...addBlockedBy])];
    }
    if (addBlocks) {
      task.blocks = [...new Set([...task.blocks, ...addBlocks])];
      for (const blockedId of addBlocks) {
        try {
          const blocked = this.load(blockedId);
          if (!blocked.blockedBy.includes(id)) {
            blocked.blockedBy.push(id);
            this.save(blocked);
          }
        } catch { /* task may not exist */ }
      }
    }
    this.save(task);
    return JSON.stringify(task, null, 2);
  }

  private clearDependency(completedId: number): void {
    const files = fs.readdirSync(this.tasksDir).filter((f) => /^task_\d+\.json$/.test(f));
    for (const f of files) {
      const task = JSON.parse(fs.readFileSync(path.join(this.tasksDir, f), "utf-8")) as Task;
      if (task.blockedBy.includes(completedId)) {
        task.blockedBy = task.blockedBy.filter((id) => id !== completedId);
        this.save(task);
      }
    }
  }

  listAll(): string {
    const files = fs.readdirSync(this.tasksDir)
      .filter((f) => /^task_\d+\.json$/.test(f))
      .sort();
    if (!files.length) return "No tasks.";
    const tasks = files.map((f) => JSON.parse(fs.readFileSync(path.join(this.tasksDir, f), "utf-8")) as Task);
    const markers: Record<string, string> = { pending: "[ ]", in_progress: "[>]", completed: "[x]" };
    const lines = tasks.map((t) => {
      const marker = markers[t.status] || "[?]";
      const blocked = t.blockedBy.length ? ` (blocked by: ${JSON.stringify(t.blockedBy)})` : "";
      return `${marker} #${t.id}: ${t.subject}${blocked}`;
    });
    return lines.join("\n");
  }
}

const TASKS = new TaskManager(TASKS_DIR);

type ToolInput = Record<string, unknown>;

function safePath(p: string): string {
  const resolved = path.resolve(WORKDIR, p);
  if (!resolved.startsWith(WORKDIR)) throw new Error(`Path escapes workspace: ${p}`);
  return resolved;
}

function runBash(command: string): string {
  const dangerous = ["rm -rf /", "sudo", "shutdown", "reboot", "> /dev/"];
  if (dangerous.some((d) => command.includes(d))) return "Error: Dangerous command blocked";
  const result = spawnSync("bash", ["-c", command], { cwd: WORKDIR, timeout: 120000, encoding: "utf-8" });
  if (result.error?.message?.includes("ETIMEDOUT")) return "Error: Timeout (120s)";
  const out = ((result.stdout || "") + (result.stderr || "")).trim();
  return (out || "(no output)").slice(0, 50000);
}

function runRead(filePath: string, limit?: number): string {
  try {
    const lines = fs.readFileSync(safePath(filePath), "utf-8").split("\n");
    const limited = (limit && limit < lines.length)
      ? [...lines.slice(0, limit), `... (${lines.length - limit} more)`]
      : lines;
    return limited.join("\n").slice(0, 50000);
  } catch (e) { return `Error: ${e}`; }
}

function runWrite(filePath: string, content: string): string {
  try {
    const fp = safePath(filePath);
    fs.mkdirSync(path.dirname(fp), { recursive: true });
    fs.writeFileSync(fp, content, "utf-8");
    return `Wrote ${content.length} bytes`;
  } catch (e) { return `Error: ${e}`; }
}

function runEdit(filePath: string, oldText: string, newText: string): string {
  try {
    const fp = safePath(filePath);
    const content = fs.readFileSync(fp, "utf-8");
    if (!content.includes(oldText)) return `Error: Text not found in ${filePath}`;
    fs.writeFileSync(fp, content.replace(oldText, newText), "utf-8");
    return `Edited ${filePath}`;
  } catch (e) { return `Error: ${e}`; }
}

const TOOL_HANDLERS: Record<string, (kw: ToolInput) => string> = {
  bash:        (kw) => runBash(kw.command as string),
  read_file:   (kw) => runRead(kw.path as string, kw.limit as number | undefined),
  write_file:  (kw) => runWrite(kw.path as string, kw.content as string),
  edit_file:   (kw) => runEdit(kw.path as string, kw.old_text as string, kw.new_text as string),
  task_create: (kw) => TASKS.create(kw.subject as string, kw.description as string | undefined),
  task_update: (kw) => TASKS.update(kw.task_id as number, kw.status as string | undefined, kw.addBlockedBy as number[] | undefined, kw.addBlocks as number[] | undefined),
  task_list:   () => TASKS.listAll(),
  task_get:    (kw) => TASKS.get(kw.task_id as number),
};

const TOOLS: Anthropic.Tool[] = [
  { name: "bash", description: "Run a shell command.",
    input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
  { name: "read_file", description: "Read file contents.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, limit: { type: "integer" } }, required: ["path"] } },
  { name: "write_file", description: "Write content to file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, content: { type: "string" } }, required: ["path", "content"] } },
  { name: "edit_file", description: "Replace exact text in file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, old_text: { type: "string" }, new_text: { type: "string" } }, required: ["path", "old_text", "new_text"] } },
  { name: "task_create", description: "Create a new task.",
    input_schema: { type: "object" as const, properties: { subject: { type: "string" }, description: { type: "string" } }, required: ["subject"] } },
  { name: "task_update", description: "Update a task's status or dependencies.",
    input_schema: { type: "object" as const, properties: { task_id: { type: "integer" }, status: { type: "string", enum: ["pending", "in_progress", "completed"] }, addBlockedBy: { type: "array", items: { type: "integer" } }, addBlocks: { type: "array", items: { type: "integer" } } }, required: ["task_id"] } },
  { name: "task_list", description: "List all tasks with status summary.",
    input_schema: { type: "object" as const, properties: {} } },
  { name: "task_get", description: "Get full details of a task by ID.",
    input_schema: { type: "object" as const, properties: { task_id: { type: "integer" } }, required: ["task_id"] } },
];

async function agentLoop(messages: Anthropic.MessageParam[]): Promise<void> {
  while (true) {
    const response = await client.messages.create({
      model: MODEL, system: SYSTEM, messages, tools: TOOLS, max_tokens: 8000,
    });
    messages.push({ role: "assistant", content: response.content });
    if (response.stop_reason !== "tool_use") return;
    const results: Anthropic.ToolResultBlockParam[] = [];
    for (const block of response.content) {
      if (block.type === "tool_use") {
        const handler = TOOL_HANDLERS[block.name];
        let output: string;
        try {
          output = handler ? handler(block.input as ToolInput) : `Unknown tool: ${block.name}`;
        } catch (e) {
          output = `Error: ${e}`;
        }
        process.stdout.write(`> ${block.name}: ${String(output).slice(0, 200)}\n`);
        results.push({ type: "tool_result", tool_use_id: block.id, content: String(output) });
      }
    }
    messages.push({ role: "user", content: results });
  }
}

async function main() {
  const history: Anthropic.MessageParam[] = [];
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
  const ask = () => new Promise<string>((resolve) => rl.question("\x1b[36ms07 >> \x1b[0m", resolve));

  while (true) {
    let query: string;
    try { query = await ask(); } catch { break; }
    if (["q", "exit", ""].includes(query.trim().toLowerCase())) break;
    history.push({ role: "user", content: query });
    await agentLoop(history);
    const last = history[history.length - 1];
    if (last.role === "assistant" && Array.isArray(last.content)) {
      for (const block of last.content) {
        if (block.type === "text") process.stdout.write(block.text + "\n");
      }
    }
    process.stdout.write("\n");
  }
  rl.close();
}

main().catch(console.error);

#!/usr/bin/env tsx
/**
 * s08_background_tasks.ts - Background Tasks
 *
 * Run commands in background. A notification queue is drained
 * before each LLM call to deliver results.
 *
 *     Main loop                   Background exec
 *     +-----------------+         +-----------------+
 *     | agent loop      |         | task executes   |
 *     | ...             |         | ...             |
 *     | [LLM call] <---+--------- | enqueue(result) |
 *     |  ^drain queue   |         +-----------------+
 *     +-----------------+
 *
 *     Timeline:
 *     Agent ----[spawn A]----[spawn B]----[other work]----
 *                  |              |
 *                  v              v
 *               [A runs]      [B runs]        (parallel)
 *                  |              |
 *                  +-- notification queue --> [results injected]
 *
 * Key insight: "Fire and forget -- the agent doesn't block while the command runs."
 */

import Anthropic from "@anthropic-ai/sdk";
import * as dotenv from "dotenv";
import { spawnSync, exec } from "child_process";
import * as fs from "fs";
import * as path from "path";
import * as readline from "readline";
import { randomUUID } from "crypto";

dotenv.config({ override: true });

const client = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
const MODEL = process.env.MODEL_ID!;
const WORKDIR = process.cwd();

const SYSTEM = `You are a coding agent at ${WORKDIR}. Use background_run for long-running commands.`;

interface BgTask {
  status: "running" | "completed" | "timeout" | "error";
  result: string | null;
  command: string;
}

interface Notification {
  task_id: string;
  status: string;
  command: string;
  result: string;
}

// -- BackgroundManager: async execution + notification queue --
class BackgroundManager {
  private tasks: Map<string, BgTask> = new Map();
  private notificationQueue: Notification[] = [];

  run(command: string): string {
    const taskId = randomUUID().slice(0, 8);
    this.tasks.set(taskId, { status: "running", result: null, command });

    exec(command, { cwd: WORKDIR, timeout: 300000 }, (error, stdout, stderr) => {
      const task = this.tasks.get(taskId)!;
      if (error && error.killed) {
        task.status = "timeout";
        task.result = "Error: Timeout (300s)";
      } else {
        task.status = "completed";
        task.result = ((stdout || "") + (stderr || "")).trim().slice(0, 50000) || "(no output)";
      }
      this.notificationQueue.push({
        task_id: taskId,
        status: task.status,
        command: command.slice(0, 80),
        result: task.result!.slice(0, 500),
      });
    });

    return `Background task ${taskId} started: ${command.slice(0, 80)}`;
  }

  check(taskId?: string): string {
    if (taskId) {
      const t = this.tasks.get(taskId);
      if (!t) return `Error: Unknown task ${taskId}`;
      return `[${t.status}] ${t.command.slice(0, 60)}\n${t.result || "(running)"}`;
    }
    const lines: string[] = [];
    for (const [tid, t] of this.tasks) {
      lines.push(`${tid}: [${t.status}] ${t.command.slice(0, 60)}`);
    }
    return lines.join("\n") || "No background tasks.";
  }

  drainNotifications(): Notification[] {
    const notifs = [...this.notificationQueue];
    this.notificationQueue.length = 0;
    return notifs;
  }
}

const BG = new BackgroundManager();

type ToolInput = Record<string, unknown>;

function safePath(p: string): string {
  const resolved = path.resolve(WORKDIR, p);
  if (!resolved.startsWith(WORKDIR)) throw new Error(`Path escapes workspace: ${p}`);
  return resolved;
}

function runBash(command: string): string {
  const dangerous = ["rm -rf /", "sudo", "shutdown", "reboot", "> /dev/"];
  if (dangerous.some((d) => command.includes(d))) return "Error: Dangerous command blocked";
  const result = spawnSync("bash", ["-c", command], { cwd: WORKDIR, timeout: 120000, encoding: "utf-8" });
  if (result.error?.message?.includes("ETIMEDOUT")) return "Error: Timeout (120s)";
  const out = ((result.stdout || "") + (result.stderr || "")).trim();
  return (out || "(no output)").slice(0, 50000);
}

function runRead(filePath: string, limit?: number): string {
  try {
    const lines = fs.readFileSync(safePath(filePath), "utf-8").split("\n");
    const limited = (limit && limit < lines.length)
      ? [...lines.slice(0, limit), `... (${lines.length - limit} more)`]
      : lines;
    return limited.join("\n").slice(0, 50000);
  } catch (e) { return `Error: ${e}`; }
}

function runWrite(filePath: string, content: string): string {
  try {
    const fp = safePath(filePath);
    fs.mkdirSync(path.dirname(fp), { recursive: true });
    fs.writeFileSync(fp, content, "utf-8");
    return `Wrote ${content.length} bytes`;
  } catch (e) { return `Error: ${e}`; }
}

function runEdit(filePath: string, oldText: string, newText: string): string {
  try {
    const fp = safePath(filePath);
    const content = fs.readFileSync(fp, "utf-8");
    if (!content.includes(oldText)) return `Error: Text not found in ${filePath}`;
    fs.writeFileSync(fp, content.replace(oldText, newText), "utf-8");
    return `Edited ${filePath}`;
  } catch (e) { return `Error: ${e}`; }
}

const TOOL_HANDLERS: Record<string, (kw: ToolInput) => string> = {
  bash:             (kw) => runBash(kw.command as string),
  read_file:        (kw) => runRead(kw.path as string, kw.limit as number | undefined),
  write_file:       (kw) => runWrite(kw.path as string, kw.content as string),
  edit_file:        (kw) => runEdit(kw.path as string, kw.old_text as string, kw.new_text as string),
  background_run:   (kw) => BG.run(kw.command as string),
  check_background: (kw) => BG.check(kw.task_id as string | undefined),
};

const TOOLS: Anthropic.Tool[] = [
  { name: "bash", description: "Run a shell command (blocking).",
    input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
  { name: "read_file", description: "Read file contents.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, limit: { type: "integer" } }, required: ["path"] } },
  { name: "write_file", description: "Write content to file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, content: { type: "string" } }, required: ["path", "content"] } },
  { name: "edit_file", description: "Replace exact text in file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, old_text: { type: "string" }, new_text: { type: "string" } }, required: ["path", "old_text", "new_text"] } },
  { name: "background_run", description: "Run command in background. Returns task_id immediately.",
    input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
  { name: "check_background", description: "Check background task status. Omit task_id to list all.",
    input_schema: { type: "object" as const, properties: { task_id: { type: "string" } } } },
];

async function agentLoop(messages: Anthropic.MessageParam[]): Promise<void> {
  while (true) {
    // Drain background notifications and inject as system message before LLM call
    const notifs = BG.drainNotifications();
    if (notifs.length && messages.length) {
      const notifText = notifs.map((n) => `[bg:${n.task_id}] ${n.status}: ${n.result}`).join("\n");
      messages.push({ role: "user", content: `<background-results>\n${notifText}\n</background-results>` });
      messages.push({ role: "assistant", content: "Noted background results." });
    }
    const response = await client.messages.create({
      model: MODEL, system: SYSTEM, messages, tools: TOOLS, max_tokens: 8000,
    });
    messages.push({ role: "assistant", content: response.content });
    if (response.stop_reason !== "tool_use") return;
    const results: Anthropic.ToolResultBlockParam[] = [];
    for (const block of response.content) {
      if (block.type === "tool_use") {
        const handler = TOOL_HANDLERS[block.name];
        let output: string;
        try {
          output = handler ? handler(block.input as ToolInput) : `Unknown tool: ${block.name}`;
        } catch (e) {
          output = `Error: ${e}`;
        }
        process.stdout.write(`> ${block.name}: ${String(output).slice(0, 200)}\n`);
        results.push({ type: "tool_result", tool_use_id: block.id, content: String(output) });
      }
    }
    messages.push({ role: "user", content: results });
  }
}

async function main() {
  const history: Anthropic.MessageParam[] = [];
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
  const ask = () => new Promise<string>((resolve) => rl.question("\x1b[36ms08 >> \x1b[0m", resolve));

  while (true) {
    let query: string;
    try { query = await ask(); } catch { break; }
    if (["q", "exit", ""].includes(query.trim().toLowerCase())) break;
    history.push({ role: "user", content: query });
    await agentLoop(history);
    const last = history[history.length - 1];
    if (last.role === "assistant" && Array.isArray(last.content)) {
      for (const block of last.content) {
        if (block.type === "text") process.stdout.write(block.text + "\n");
      }
    }
    process.stdout.write("\n");
  }
  rl.close();
}

main().catch(console.error);

#!/usr/bin/env tsx
/**
 * s09_agent_teams.ts - Agent Teams
 *
 * Persistent named agents with file-based JSONL inboxes. Each teammate runs
 * its own agent loop in a separate Worker thread. Communication via append-only inboxes.
 *
 *     Subagent (s04):  spawn -> execute -> return summary -> destroyed
 *     Teammate (s09):  spawn -> work -> idle -> work -> ... -> shutdown
 *
 *     .team/config.json                   .team/inbox/
 *     +----------------------------+      +------------------+
 *     | {"team_name": "default",   |      | alice.jsonl      |
 *     |  "members": [              |      | bob.jsonl        |
 *     |    {"name":"alice",        |      | lead.jsonl       |
 *     |     "role":"coder",        |      +------------------+
 *     |     "status":"idle"}       |
 *     |  ]}                        |
 *     +----------------------------+
 *
 * Key insight: "Teammates that can talk to each other."
 */

import Anthropic from "@anthropic-ai/sdk";
import * as dotenv from "dotenv";
import { spawnSync } from "child_process";
import * as fs from "fs";
import * as path from "path";
import * as readline from "readline";
import { Worker, isMainThread, parentPort, workerData } from "worker_threads";

dotenv.config({ override: true });

const WORKDIR = process.cwd();
const TEAM_DIR = path.join(WORKDIR, ".team");
const INBOX_DIR = path.join(TEAM_DIR, "inbox");

const VALID_MSG_TYPES = new Set([
  "message", "broadcast", "shutdown_request", "shutdown_response", "plan_approval_response",
]);

// -- MessageBus: JSONL inbox per teammate --
class MessageBus {
  constructor(private inboxDir: string) {
    fs.mkdirSync(inboxDir, { recursive: true });
  }

  send(sender: string, to: string, content: string, msgType = "message", extra?: Record<string, unknown>): string {
    if (!VALID_MSG_TYPES.has(msgType)) {
      return `Error: Invalid type '${msgType}'. Valid: ${[...VALID_MSG_TYPES].join(", ")}`;
    }
    const msg: Record<string, unknown> = {
      type: msgType, from: sender, content, timestamp: Date.now() / 1000,
    };
    if (extra) Object.assign(msg, extra);
    const inboxPath = path.join(this.inboxDir, `${to}.jsonl`);
    fs.appendFileSync(inboxPath, JSON.stringify(msg) + "\n", "utf-8");
    return `Sent ${msgType} to ${to}`;
  }

  readInbox(name: string): Record<string, unknown>[] {
    const inboxPath = path.join(this.inboxDir, `${name}.jsonl`);
    if (!fs.existsSync(inboxPath)) return [];
    const msgs = fs.readFileSync(inboxPath, "utf-8")
      .trim().split("\n").filter(Boolean)
      .map((l) => JSON.parse(l) as Record<string, unknown>);
    fs.writeFileSync(inboxPath, "", "utf-8");
    return msgs;
  }

  broadcast(sender: string, content: string, teammates: string[]): string {
    let count = 0;
    for (const name of teammates) {
      if (name !== sender) { this.send(sender, name, content, "broadcast"); count++; }
    }
    return `Broadcast to ${count} teammates`;
  }
}

const BUS = new MessageBus(INBOX_DIR);

interface TeamMember {
  name: string;
  role: string;
  status: "working" | "idle" | "shutdown";
}

interface TeamConfig {
  team_name: string;
  members: TeamMember[];
}

// -- TeammateManager: persistent named agents with config.json --
class TeammateManager {
  private configPath: string;
  private config: TeamConfig;

  constructor(private teamDir: string) {
    fs.mkdirSync(teamDir, { recursive: true });
    this.configPath = path.join(teamDir, "config.json");
    this.config = this.loadConfig();
  }

  private loadConfig(): TeamConfig {
    if (fs.existsSync(this.configPath)) {
      return JSON.parse(fs.readFileSync(this.configPath, "utf-8")) as TeamConfig;
    }
    return { team_name: "default", members: [] };
  }

  private saveConfig(): void {
    fs.writeFileSync(this.configPath, JSON.stringify(this.config, null, 2), "utf-8");
  }

  private findMember(name: string): TeamMember | undefined {
    return this.config.members.find((m) => m.name === name);
  }

  spawn(name: string, role: string, prompt: string): string {
    let member = this.findMember(name);
    if (member) {
      if (!["idle", "shutdown"].includes(member.status)) {
        return `Error: '${name}' is currently ${member.status}`;
      }
      member.status = "working";
      member.role = role;
    } else {
      member = { name, role, status: "working" };
      this.config.members.push(member);
    }
    this.saveConfig();

    // Run teammate in worker thread
    const worker = new Worker(__filename, {
      workerData: { mode: "teammate", name, role, prompt, workdir: WORKDIR, teamDir: this.teamDir, inboxDir: INBOX_DIR },
    });
    worker.on("exit", () => {
      // Worker exited - update status if still working
      const m = this.findMember(name);
      if (m && m.status === "working") {
        m.status = "idle";
        this.saveConfig();
      }
    });
    return `Spawned '${name}' (role: ${role})`;
  }

  listAll(): string {
    if (!this.config.members.length) return "No teammates.";
    // Re-read config to get latest status
    this.config = this.loadConfig();
    const lines = [`Team: ${this.config.team_name}`];
    for (const m of this.config.members) {
      lines.push(`  ${m.name} (${m.role}): ${m.status}`);
    }
    return lines.join("\n");
  }

  memberNames(): string[] {
    return this.config.members.map((m) => m.name);
  }
}

const TEAM = new TeammateManager(TEAM_DIR);

type ToolInput = Record<string, unknown>;

function safePath(p: string, workdir = WORKDIR): string {
  const resolved = path.resolve(workdir, p);
  if (!resolved.startsWith(workdir)) throw new Error(`Path escapes workspace: ${p}`);
  return resolved;
}

function runBash(command: string, cwd = WORKDIR): string {
  const dangerous = ["rm -rf /", "sudo", "shutdown", "reboot"];
  if (dangerous.some((d) => command.includes(d))) return "Error: Dangerous command blocked";
  const result = spawnSync("bash", ["-c", command], { cwd, timeout: 120000, encoding: "utf-8" });
  if (result.error?.message?.includes("ETIMEDOUT")) return "Error: Timeout (120s)";
  const out = ((result.stdout || "") + (result.stderr || "")).trim();
  return (out || "(no output)").slice(0, 50000);
}

function runRead(filePath: string, workdir = WORKDIR): string {
  try {
    return fs.readFileSync(safePath(filePath, workdir), "utf-8").slice(0, 50000);
  } catch (e) { return `Error: ${e}`; }
}

function runWrite(filePath: string, content: string, workdir = WORKDIR): string {
  try {
    const fp = safePath(filePath, workdir);
    fs.mkdirSync(path.dirname(fp), { recursive: true });
    fs.writeFileSync(fp, content, "utf-8");
    return `Wrote ${content.length} bytes`;
  } catch (e) { return `Error: ${e}`; }
}

function runEdit(filePath: string, oldText: string, newText: string, workdir = WORKDIR): string {
  try {
    const fp = safePath(filePath, workdir);
    const content = fs.readFileSync(fp, "utf-8");
    if (!content.includes(oldText)) return `Error: Text not found in ${filePath}`;
    fs.writeFileSync(fp, content.replace(oldText, newText), "utf-8");
    return `Edited ${filePath}`;
  } catch (e) { return `Error: ${e}`; }
}

// -- Lead tool dispatch --
const TOOL_HANDLERS: Record<string, (kw: ToolInput) => string> = {
  bash:           (kw) => runBash(kw.command as string),
  read_file:      (kw) => runRead(kw.path as string),
  write_file:     (kw) => runWrite(kw.path as string, kw.content as string),
  edit_file:      (kw) => runEdit(kw.path as string, kw.old_text as string, kw.new_text as string),
  spawn_teammate: (kw) => TEAM.spawn(kw.name as string, kw.role as string, kw.prompt as string),
  list_teammates: () => TEAM.listAll(),
  send_message:   (kw) => BUS.send("lead", kw.to as string, kw.content as string, (kw.msg_type as string) || "message"),
  read_inbox:     () => JSON.stringify(BUS.readInbox("lead"), null, 2),
  broadcast:      (kw) => BUS.broadcast("lead", kw.content as string, TEAM.memberNames()),
};

const TOOLS: Anthropic.Tool[] = [
  { name: "bash", description: "Run a shell command.",
    input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
  { name: "read_file", description: "Read file contents.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, limit: { type: "integer" } }, required: ["path"] } },
  { name: "write_file", description: "Write content to file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, content: { type: "string" } }, required: ["path", "content"] } },
  { name: "edit_file", description: "Replace exact text in file.",
    input_schema: { type: "object" as const, properties: { path: { type: "string" }, old_text: { type: "string" }, new_text: { type: "string" } }, required: ["path", "old_text", "new_text"] } },
  { name: "spawn_teammate", description: "Spawn a persistent teammate that runs in its own thread.",
    input_schema: { type: "object" as const, properties: { name: { type: "string" }, role: { type: "string" }, prompt: { type: "string" } }, required: ["name", "role", "prompt"] } },
  { name: "list_teammates", description: "List all teammates with name, role, status.",
    input_schema: { type: "object" as const, properties: {} } },
  { name: "send_message", description: "Send a message to a teammate's inbox.",
    input_schema: { type: "object" as const, properties: { to: { type: "string" }, content: { type: "string" }, msg_type: { type: "string", enum: [...VALID_MSG_TYPES] } }, required: ["to", "content"] } },
  { name: "read_inbox", description: "Read and drain the lead's inbox.",
    input_schema: { type: "object" as const, properties: {} } },
  { name: "broadcast", description: "Send a message to all teammates.",
    input_schema: { type: "object" as const, properties: { content: { type: "string" } }, required: ["content"] } },
];

async function agentLoop(messages: Anthropic.MessageParam[], system: string, tools: Anthropic.Tool[]): Promise<void> {
  while (true) {
    const inbox = BUS.readInbox("lead");
    if (inbox.length) {
      messages.push({ role: "user", content: `<inbox>${JSON.stringify(inbox, null, 2)}</inbox>` });
      messages.push({ role: "assistant", content: "Noted inbox messages." });
    }
    const response = await client.messages.create({
      model: MODEL, system, messages, tools, max_tokens: 8000,
    });
    messages.push({ role: "assistant", content: response.content });
    if (response.stop_reason !== "tool_use") return;
    const results: Anthropic.ToolResultBlockParam[] = [];
    for (const block of response.content) {
      if (block.type === "tool_use") {
        const handler = TOOL_HANDLERS[block.name];
        let output: string;
        try {
          output = handler ? handler(block.input as ToolInput) : `Unknown tool: ${block.name}`;
        } catch (e) {
          output = `Error: ${e}`;
        }
        process.stdout.write(`> ${block.name}: ${String(output).slice(0, 200)}\n`);
        results.push({ type: "tool_result", tool_use_id: block.id, content: String(output) });
      }
    }
    messages.push({ role: "user", content: results });
  }
}

// -- Worker thread: teammate loop --
if (!isMainThread) {
  const { mode, name, role, prompt, workdir, inboxDir } = workerData as {
    mode: string; name: string; role: string; prompt: string;
    workdir: string; teamDir: string; inboxDir: string;
  };

  if (mode === "teammate") {
    const client2 = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
    const model2 = process.env.MODEL_ID!;
    const bus = new MessageBus(inboxDir);

    const sysPrompt = `You are '${name}', role: ${role}, at ${workdir}. Use send_message to communicate. Complete your task.`;
    const messages: Anthropic.MessageParam[] = [{ role: "user", content: prompt }];
    const tools: Anthropic.Tool[] = [
      { name: "bash", description: "Run a shell command.",
        input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
      { name: "read_file", description: "Read file contents.",
        input_schema: { type: "object" as const, properties: { path: { type: "string" } }, required: ["path"] } },
      { name: "write_file", description: "Write content to file.",
        input_schema: { type: "object" as const, properties: { path: { type: "string" }, content: { type: "string" } }, required: ["path", "content"] } },
      { name: "edit_file", description: "Replace exact text in file.",
        input_schema: { type: "object" as const, properties: { path: { type: "string" }, old_text: { type: "string" }, new_text: { type: "string" } }, required: ["path", "old_text", "new_text"] } },
      { name: "send_message", description: "Send message to a teammate.",
        input_schema: { type: "object" as const, properties: { to: { type: "string" }, content: { type: "string" }, msg_type: { type: "string", enum: [...VALID_MSG_TYPES] } }, required: ["to", "content"] } },
      { name: "read_inbox", description: "Read and drain your inbox.",
        input_schema: { type: "object" as const, properties: {} } },
    ];

    (async () => {
      for (let i = 0; i < 50; i++) {
        const inbox = bus.readInbox(name);
        for (const msg of inbox) {
          messages.push({ role: "user", content: JSON.stringify(msg) });
        }
        let response: Anthropic.Message;
        try {
          response = await client2.messages.create({
            model: model2, system: sysPrompt, messages, tools, max_tokens: 8000,
          });
        } catch { break; }
        messages.push({ role: "assistant", content: response.content });
        if (response.stop_reason !== "tool_use") break;
        const results: Anthropic.ToolResultBlockParam[] = [];
        for (const block of response.content) {
          if (block.type === "tool_use") {
            let output: string;
            if (block.name === "bash") output = runBash((block.input as ToolInput).command as string, workdir);
            else if (block.name === "read_file") output = runRead((block.input as ToolInput).path as string, workdir);
            else if (block.name === "write_file") output = runWrite((block.input as ToolInput).path as string, (block.input as ToolInput).content as string, workdir);
            else if (block.name === "edit_file") output = runEdit((block.input as ToolInput).path as string, (block.input as ToolInput).old_text as string, (block.input as ToolInput).new_text as string, workdir);
            else if (block.name === "send_message") output = bus.send(name, (block.input as ToolInput).to as string, (block.input as ToolInput).content as string, ((block.input as ToolInput).msg_type as string) || "message");
            else if (block.name === "read_inbox") output = JSON.stringify(bus.readInbox(name), null, 2);
            else output = `Unknown tool: ${block.name}`;
            process.stdout.write(`  [${name}] ${block.name}: ${String(output).slice(0, 120)}\n`);
            results.push({ type: "tool_result", tool_use_id: block.id, content: String(output) });
          }
        }
        messages.push({ role: "user", content: results });
      }
      parentPort?.postMessage({ status: "done" });
    })().catch(() => parentPort?.postMessage({ status: "error" }));
  }
}

// -- Main thread --
const client = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
const MODEL = process.env.MODEL_ID!;
const SYSTEM = `You are a team lead at ${WORKDIR}. Spawn teammates and communicate via inboxes.`;

async function main() {
  if (!isMainThread) return;
  const history: Anthropic.MessageParam[] = [];
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
  const ask = () => new Promise<string>((resolve) => rl.question("\x1b[36ms09 >> \x1b[0m", resolve));

  while (true) {
    let query: string;
    try { query = await ask(); } catch { break; }
    if (["q", "exit", ""].includes(query.trim().toLowerCase())) break;
    if (query.trim() === "/team") { process.stdout.write(TEAM.listAll() + "\n"); continue; }
    if (query.trim() === "/inbox") { process.stdout.write(JSON.stringify(BUS.readInbox("lead"), null, 2) + "\n"); continue; }
    history.push({ role: "user", content: query });
    await agentLoop(history, SYSTEM, TOOLS);
    const last = history[history.length - 1];
    if (last.role === "assistant" && Array.isArray(last.content)) {
      for (const block of last.content) {
        if (block.type === "text") process.stdout.write(block.text + "\n");
      }
    }
    process.stdout.write("\n");
  }
  rl.close();
}

main().catch(console.error);

#!/usr/bin/env tsx
/**
 * s10_team_protocols.ts - Team Protocols
 *
 * Shutdown protocol and plan approval protocol, both using the same
 * request_id correlation pattern. Builds on s09's team messaging.
 *
 *     Shutdown FSM: pending -> approved | rejected
 *
 *     Lead                              Teammate
 *     +---------------------+          +---------------------+
 *     | shutdown_request     |          |                     |
 *     | {                    | -------> | receives request    |
 *     |   request_id: abc    |          | decides: approve?   |
 *     | }                    |          |                     |
 *     +---------------------+          +---------------------+
 *                                              |
 *     +---------------------+          +-------v-------------+
 *     | shutdown_response    | <------- | shutdown_response   |
 *     | {                    |          | {                   |
 *     |   request_id: abc    |          |   request_id: abc   |
 *     |   approve: true      |          |   approve: true     |
 *     | }                    |          | }                   |
 *     +---------------------+          +---------------------+
 *             |
 *             v
 *     status -> "shutdown", thread stops
 *
 * Key insight: "Same request_id correlation pattern, two domains."
 */

import Anthropic from "@anthropic-ai/sdk";
import * as dotenv from "dotenv";
import { spawnSync } from "child_process";
import * as fs from "fs";
import * as path from "path";
import * as readline from "readline";
import { Worker, isMainThread, parentPort, workerData } from "worker_threads";
import { randomUUID } from "crypto";

dotenv.config({ override: true });

const WORKDIR = process.cwd();
const TEAM_DIR = path.join(WORKDIR, ".team");
const INBOX_DIR = path.join(TEAM_DIR, "inbox");

const VALID_MSG_TYPES = new Set([
  "message", "broadcast", "shutdown_request", "shutdown_response", "plan_approval_response",
]);

// -- Request trackers --
const shutdownRequests: Map<string, { target: string; status: string }> = new Map();
const planRequests: Map<string, { from: string; plan: string; status: string }> = new Map();

class MessageBus {
  constructor(private inboxDir: string) {
    fs.mkdirSync(inboxDir, { recursive: true });
  }

  send(sender: string, to: string, content: string, msgType = "message", extra?: Record<string, unknown>): string {
    if (!VALID_MSG_TYPES.has(msgType)) {
      return `Error: Invalid type '${msgType}'. Valid: ${[...VALID_MSG_TYPES].join(", ")}`;
    }
    const msg: Record<string, unknown> = { type: msgType, from: sender, content, timestamp: Date.now() / 1000 };
    if (extra) Object.assign(msg, extra);
    fs.appendFileSync(path.join(this.inboxDir, `${to}.jsonl`), JSON.stringify(msg) + "\n", "utf-8");
    return `Sent ${msgType} to ${to}`;
  }

  readInbox(name: string): Record<string, unknown>[] {
    const p = path.join(this.inboxDir, `${name}.jsonl`);
    if (!fs.existsSync(p)) return [];
    const msgs = fs.readFileSync(p, "utf-8").trim().split("\n").filter(Boolean)
      .map((l) => JSON.parse(l) as Record<string, unknown>);
    fs.writeFileSync(p, "", "utf-8");
    return msgs;
  }

  broadcast(sender: string, content: string, teammates: string[]): string {
    let count = 0;
    for (const name of teammates) {
      if (name !== sender) { this.send(sender, name, content, "broadcast"); count++; }
    }
    return `Broadcast to ${count} teammates`;
  }
}

const BUS = new MessageBus(INBOX_DIR);

interface TeamMember { name: string; role: string; status: string; }
interface TeamConfig { team_name: string; members: TeamMember[]; }

class TeammateManager {
  private configPath: string;
  private config: TeamConfig;

  constructor(private teamDir: string) {
    fs.mkdirSync(teamDir, { recursive: true });
    this.configPath = path.join(teamDir, "config.json");
    this.config = this.loadConfig();
  }

  private loadConfig(): TeamConfig {
    if (fs.existsSync(this.configPath)) return JSON.parse(fs.readFileSync(this.configPath, "utf-8")) as TeamConfig;
    return { team_name: "default", members: [] };
  }

  private saveConfig(): void {
    fs.writeFileSync(this.configPath, JSON.stringify(this.config, null, 2), "utf-8");
  }

  private findMember(name: string): TeamMember | undefined {
    return this.config.members.find((m) => m.name === name);
  }

  spawn(name: string, role: string, prompt: string): string {
    let member = this.findMember(name);
    if (member) {
      if (!["idle", "shutdown"].includes(member.status)) return `Error: '${name}' is currently ${member.status}`;
      member.status = "working"; member.role = role;
    } else {
      member = { name, role, status: "working" };
      this.config.members.push(member);
    }
    this.saveConfig();
    const worker = new Worker(__filename, {
      workerData: { mode: "teammate", name, role, prompt, workdir: WORKDIR, teamDir: this.teamDir, inboxDir: INBOX_DIR },
    });
    worker.on("exit", () => {
      const m = this.findMember(name);
      if (m && m.status === "working") { m.status = "idle"; this.saveConfig(); }
    });
    return `Spawned '${name}' (role: ${role})`;
  }

  listAll(): string {
    if (!this.config.members.length) return "No teammates.";
    this.config = this.loadConfig();
    return [`Team: ${this.config.team_name}`, ...this.config.members.map((m) => `  ${m.name} (${m.role}): ${m.status}`)].join("\n");
  }

  memberNames(): string[] { return this.config.members.map((m) => m.name); }
}

const TEAM = new TeammateManager(TEAM_DIR);

type ToolInput = Record<string, unknown>;

function runBash(command: string, cwd = WORKDIR): string {
  const dangerous = ["rm -rf /", "sudo", "shutdown", "reboot"];
  if (dangerous.some((d) => command.includes(d))) return "Error: Dangerous command blocked";
  const result = spawnSync("bash", ["-c", command], { cwd, timeout: 120000, encoding: "utf-8" });
  if (result.error?.message?.includes("ETIMEDOUT")) return "Error: Timeout (120s)";
  const out = ((result.stdout || "") + (result.stderr || "")).trim();
  return (out || "(no output)").slice(0, 50000);
}

function runRead(filePath: string, workdir = WORKDIR): string {
  try { return fs.readFileSync(path.resolve(workdir, filePath), "utf-8").slice(0, 50000); }
  catch (e) { return `Error: ${e}`; }
}

function runWrite(filePath: string, content: string, workdir = WORKDIR): string {
  try {
    const fp = path.resolve(workdir, filePath);
    fs.mkdirSync(path.dirname(fp), { recursive: true });
    fs.writeFileSync(fp, content, "utf-8");
    return `Wrote ${content.length} bytes`;
  } catch (e) { return `Error: ${e}`; }
}

function runEdit(filePath: string, oldText: string, newText: string, workdir = WORKDIR): string {
  try {
    const fp = path.resolve(workdir, filePath);
    const content = fs.readFileSync(fp, "utf-8");
    if (!content.includes(oldText)) return `Error: Text not found in ${filePath}`;
    fs.writeFileSync(fp, content.replace(oldText, newText), "utf-8");
    return `Edited ${filePath}`;
  } catch (e) { return `Error: ${e}`; }
}

// -- Lead-specific protocol handlers --
function handleShutdownRequest(teammate: string): string {
  const reqId = randomUUID().slice(0, 8);
  shutdownRequests.set(reqId, { target: teammate, status: "pending" });
  BUS.send("lead", teammate, "Please shut down gracefully.", "shutdown_request", { request_id: reqId });
  return `Shutdown request ${reqId} sent to '${teammate}' (status: pending)`;
}

function handlePlanReview(requestId: string, approve: boolean, feedback = ""): string {
  const req = planRequests.get(requestId);
  if (!req) return `Error: Unknown plan request_id '${requestId}'`;
  req.status = approve ? "approved" : "rejected";
  BUS.send("lead", req.from, feedback, "plan_approval_response", { request_id: requestId, approve, feedback });
  return `Plan ${req.status} for '${req.from}'`;
}

function checkShutdownStatus(requestId: string): string {
  const req = shutdownRequests.get(requestId);
  return JSON.stringify(req || { error: "not found" });
}

const TOOL_HANDLERS: Record<string, (kw: ToolInput) => string> = {
  bash:              (kw) => runBash(kw.command as string),
  read_file:         (kw) => runRead(kw.path as string),
  write_file:        (kw) => runWrite(kw.path as string, kw.content as string),
  edit_file:         (kw) => runEdit(kw.path as string, kw.old_text as string, kw.new_text as string),
  spawn_teammate:    (kw) => TEAM.spawn(kw.name as string, kw.role as string, kw.prompt as string),
  list_teammates:    () => TEAM.listAll(),
  send_message:      (kw) => BUS.send("lead", kw.to as string, kw.content as string, (kw.msg_type as string) || "message"),
  read_inbox:        () => JSON.stringify(BUS.readInbox("lead"), null, 2),
  broadcast:         (kw) => BUS.broadcast("lead", kw.content as string, TEAM.memberNames()),
  shutdown_request:  (kw) => handleShutdownRequest(kw.teammate as string),
  shutdown_response: (kw) => checkShutdownStatus(kw.request_id as string),
  plan_approval:     (kw) => handlePlanReview(kw.request_id as string, kw.approve as boolean, kw.feedback as string),
};

const TOOLS: Anthropic.Tool[] = [
  { name: "bash", description: "Run a shell command.", input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
  { name: "read_file", description: "Read file contents.", input_schema: { type: "object" as const, properties: { path: { type: "string" }, limit: { type: "integer" } }, required: ["path"] } },
  { name: "write_file", description: "Write content to file.", input_schema: { type: "object" as const, properties: { path: { type: "string" }, content: { type: "string" } }, required: ["path", "content"] } },
  { name: "edit_file", description: "Replace exact text in file.", input_schema: { type: "object" as const, properties: { path: { type: "string" }, old_text: { type: "string" }, new_text: { type: "string" } }, required: ["path", "old_text", "new_text"] } },
  { name: "spawn_teammate", description: "Spawn a persistent teammate.", input_schema: { type: "object" as const, properties: { name: { type: "string" }, role: { type: "string" }, prompt: { type: "string" } }, required: ["name", "role", "prompt"] } },
  { name: "list_teammates", description: "List all teammates.", input_schema: { type: "object" as const, properties: {} } },
  { name: "send_message", description: "Send a message to a teammate.", input_schema: { type: "object" as const, properties: { to: { type: "string" }, content: { type: "string" }, msg_type: { type: "string", enum: [...VALID_MSG_TYPES] } }, required: ["to", "content"] } },
  { name: "read_inbox", description: "Read and drain the lead's inbox.", input_schema: { type: "object" as const, properties: {} } },
  { name: "broadcast", description: "Send a message to all teammates.", input_schema: { type: "object" as const, properties: { content: { type: "string" } }, required: ["content"] } },
  { name: "shutdown_request", description: "Request a teammate to shut down gracefully. Returns a request_id for tracking.", input_schema: { type: "object" as const, properties: { teammate: { type: "string" } }, required: ["teammate"] } },
  { name: "shutdown_response", description: "Check the status of a shutdown request by request_id.", input_schema: { type: "object" as const, properties: { request_id: { type: "string" } }, required: ["request_id"] } },
  { name: "plan_approval", description: "Approve or reject a teammate's plan. Provide request_id + approve + optional feedback.", input_schema: { type: "object" as const, properties: { request_id: { type: "string" }, approve: { type: "boolean" }, feedback: { type: "string" } }, required: ["request_id", "approve"] } },
];

// -- Worker thread: teammate with shutdown + plan approval --
if (!isMainThread) {
  const { mode, name, role, prompt, workdir, inboxDir } = workerData as {
    mode: string; name: string; role: string; prompt: string;
    workdir: string; teamDir: string; inboxDir: string;
  };

  if (mode === "teammate") {
    const client2 = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
    const model2 = process.env.MODEL_ID!;
    const bus = new MessageBus(inboxDir);
    const localPlanRequests: Map<string, { from: string; plan: string; status: string }> = new Map();

    const sysPrompt = `You are '${name}', role: ${role}, at ${workdir}. Submit plans via plan_approval before major work. Respond to shutdown_request with shutdown_response.`;
    const messages: Anthropic.MessageParam[] = [{ role: "user", content: prompt }];
    const tools: Anthropic.Tool[] = [
      { name: "bash", description: "Run a shell command.", input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
      { name: "read_file", description: "Read file contents.", input_schema: { type: "object" as const, properties: { path: { type: "string" } }, required: ["path"] } },
      { name: "write_file", description: "Write content to file.", input_schema: { type: "object" as const, properties: { path: { type: "string" }, content: { type: "string" } }, required: ["path", "content"] } },
      { name: "edit_file", description: "Replace exact text in file.", input_schema: { type: "object" as const, properties: { path: { type: "string" }, old_text: { type: "string" }, new_text: { type: "string" } }, required: ["path", "old_text", "new_text"] } },
      { name: "send_message", description: "Send message to a teammate.", input_schema: { type: "object" as const, properties: { to: { type: "string" }, content: { type: "string" }, msg_type: { type: "string", enum: [...VALID_MSG_TYPES] } }, required: ["to", "content"] } },
      { name: "read_inbox", description: "Read and drain your inbox.", input_schema: { type: "object" as const, properties: {} } },
      { name: "shutdown_response", description: "Respond to a shutdown request.", input_schema: { type: "object" as const, properties: { request_id: { type: "string" }, approve: { type: "boolean" }, reason: { type: "string" } }, required: ["request_id", "approve"] } },
      { name: "plan_approval", description: "Submit a plan for lead approval.", input_schema: { type: "object" as const, properties: { plan: { type: "string" } }, required: ["plan"] } },
    ];

    (async () => {
      let shouldExit = false;
      for (let i = 0; i < 50 && !shouldExit; i++) {
        const inbox = bus.readInbox(name);
        for (const msg of inbox) messages.push({ role: "user", content: JSON.stringify(msg) });
        let response: Anthropic.Message;
        try { response = await client2.messages.create({ model: model2, system: sysPrompt, messages, tools, max_tokens: 8000 }); }
        catch { break; }
        messages.push({ role: "assistant", content: response.content });
        if (response.stop_reason !== "tool_use") break;
        const results: Anthropic.ToolResultBlockParam[] = [];
        for (const block of response.content) {
          if (block.type === "tool_use") {
            const inp = block.input as ToolInput;
            let output: string;
            if (block.name === "bash") output = runBash(inp.command as string, workdir);
            else if (block.name === "read_file") output = runRead(inp.path as string, workdir);
            else if (block.name === "write_file") output = runWrite(inp.path as string, inp.content as string, workdir);
            else if (block.name === "edit_file") output = runEdit(inp.path as string, inp.old_text as string, inp.new_text as string, workdir);
            else if (block.name === "send_message") output = bus.send(name, inp.to as string, inp.content as string, (inp.msg_type as string) || "message");
            else if (block.name === "read_inbox") output = JSON.stringify(bus.readInbox(name), null, 2);
            else if (block.name === "shutdown_response") {
              const reqId = inp.request_id as string;
              const approve = inp.approve as boolean;
              bus.send(name, "lead", (inp.reason as string) || "", "shutdown_response", { request_id: reqId, approve });
              output = `Shutdown ${approve ? "approved" : "rejected"}`;
              if (approve) shouldExit = true;
            } else if (block.name === "plan_approval") {
              const planText = (inp.plan as string) || "";
              const reqId = randomUUID().slice(0, 8);
              localPlanRequests.set(reqId, { from: name, plan: planText, status: "pending" });
              bus.send(name, "lead", planText, "plan_approval_response", { request_id: reqId, plan: planText });
              output = `Plan submitted (request_id=${reqId}). Waiting for lead approval.`;
            } else output = `Unknown tool: ${block.name}`;
            process.stdout.write(`  [${name}] ${block.name}: ${String(output).slice(0, 120)}\n`);
            results.push({ type: "tool_result", tool_use_id: block.id, content: String(output) });
          }
        }
        messages.push({ role: "user", content: results });
      }
      parentPort?.postMessage({ status: "done" });
    })().catch(() => parentPort?.postMessage({ status: "error" }));
  }
}

// -- Main thread --
const client = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
const MODEL = process.env.MODEL_ID!;
const SYSTEM = `You are a team lead at ${WORKDIR}. Manage teammates with shutdown and plan approval protocols.`;

async function agentLoop(messages: Anthropic.MessageParam[]): Promise<void> {
  while (true) {
    const inbox = BUS.readInbox("lead");
    if (inbox.length) {
      messages.push({ role: "user", content: `<inbox>${JSON.stringify(inbox, null, 2)}</inbox>` });
      messages.push({ role: "assistant", content: "Noted inbox messages." });
    }
    const response = await client.messages.create({ model: MODEL, system: SYSTEM, messages, tools: TOOLS, max_tokens: 8000 });
    messages.push({ role: "assistant", content: response.content });
    if (response.stop_reason !== "tool_use") return;
    const results: Anthropic.ToolResultBlockParam[] = [];
    for (const block of response.content) {
      if (block.type === "tool_use") {
        const handler = TOOL_HANDLERS[block.name];
        let output: string;
        try { output = handler ? handler(block.input as ToolInput) : `Unknown tool: ${block.name}`; }
        catch (e) { output = `Error: ${e}`; }
        process.stdout.write(`> ${block.name}: ${String(output).slice(0, 200)}\n`);
        results.push({ type: "tool_result", tool_use_id: block.id, content: String(output) });
      }
    }
    messages.push({ role: "user", content: results });
  }
}

async function main() {
  if (!isMainThread) return;
  const history: Anthropic.MessageParam[] = [];
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
  const ask = () => new Promise<string>((resolve) => rl.question("\x1b[36ms10 >> \x1b[0m", resolve));

  while (true) {
    let query: string;
    try { query = await ask(); } catch { break; }
    if (["q", "exit", ""].includes(query.trim().toLowerCase())) break;
    if (query.trim() === "/team") { process.stdout.write(TEAM.listAll() + "\n"); continue; }
    if (query.trim() === "/inbox") { process.stdout.write(JSON.stringify(BUS.readInbox("lead"), null, 2) + "\n"); continue; }
    history.push({ role: "user", content: query });
    await agentLoop(history);
    const last = history[history.length - 1];
    if (last.role === "assistant" && Array.isArray(last.content)) {
      for (const block of last.content) {
        if (block.type === "text") process.stdout.write(block.text + "\n");
      }
    }
    process.stdout.write("\n");
  }
  rl.close();
}

main().catch(console.error);

#!/usr/bin/env tsx
/**
 * s11_autonomous_agents.ts - Autonomous Agents
 *
 * Idle cycle with task board polling, auto-claiming unclaimed tasks, and
 * identity re-injection after context compression. Builds on s10's protocols.
 *
 *     Teammate lifecycle:
 *     +-------+
 *     | spawn |
 *     +---+---+
 *         |
 *         v
 *     +-------+  tool_use    +-------+
 *     | WORK  | <----------- |  LLM  |
 *     +---+---+              +-------+
 *         |
 *         | stop_reason != tool_use
 *         v
 *     +--------+
 *     | IDLE   | poll every 5s for up to 60s
 *     +---+----+
 *         |
 *         +---> check inbox -> message? -> resume WORK
 *         |
 *         +---> scan .tasks/ -> unclaimed? -> claim -> resume WORK
 *         |
 *         +---> timeout (60s) -> shutdown
 *
 * Key insight: "The agent finds work itself."
 */

import Anthropic from "@anthropic-ai/sdk";
import * as dotenv from "dotenv";
import { spawnSync } from "child_process";
import * as fs from "fs";
import * as path from "path";
import * as readline from "readline";
import { Worker, isMainThread, parentPort, workerData } from "worker_threads";
import { randomUUID } from "crypto";

dotenv.config({ override: true });

const WORKDIR = process.cwd();
const TEAM_DIR = path.join(WORKDIR, ".team");
const INBOX_DIR = path.join(TEAM_DIR, "inbox");
const TASKS_DIR = path.join(WORKDIR, ".tasks");

const POLL_INTERVAL = 5000; // 5 seconds
const IDLE_TIMEOUT = 60000; // 60 seconds

const VALID_MSG_TYPES = new Set([
  "message", "broadcast", "shutdown_request", "shutdown_response", "plan_approval_response",
]);

// -- Request trackers --
const shutdownRequests: Map<string, { target: string; status: string }> = new Map();
const planRequests: Map<string, { from: string; plan: string; status: string }> = new Map();

class MessageBus {
  constructor(private inboxDir: string) { fs.mkdirSync(inboxDir, { recursive: true }); }

  send(sender: string, to: string, content: string, msgType = "message", extra?: Record<string, unknown>): string {
    if (!VALID_MSG_TYPES.has(msgType)) return `Error: Invalid type '${msgType}'.`;
    const msg: Record<string, unknown> = { type: msgType, from: sender, content, timestamp: Date.now() / 1000 };
    if (extra) Object.assign(msg, extra);
    fs.appendFileSync(path.join(this.inboxDir, `${to}.jsonl`), JSON.stringify(msg) + "\n", "utf-8");
    return `Sent ${msgType} to ${to}`;
  }

  readInbox(name: string): Record<string, unknown>[] {
    const p = path.join(this.inboxDir, `${name}.jsonl`);
    if (!fs.existsSync(p)) return [];
    const msgs = fs.readFileSync(p, "utf-8").trim().split("\n").filter(Boolean)
      .map((l) => JSON.parse(l) as Record<string, unknown>);
    fs.writeFileSync(p, "", "utf-8");
    return msgs;
  }

  broadcast(sender: string, content: string, teammates: string[]): string {
    let count = 0;
    for (const name of teammates) {
      if (name !== sender) { this.send(sender, name, content, "broadcast"); count++; }
    }
    return `Broadcast to ${count} teammates`;
  }
}

const BUS = new MessageBus(INBOX_DIR);

interface TeamMember { name: string; role: string; status: string; }
interface TeamConfig { team_name: string; members: TeamMember[]; }

class TeammateManager {
  private configPath: string;
  private config: TeamConfig;

  constructor(private teamDir: string) {
    fs.mkdirSync(teamDir, { recursive: true });
    this.configPath = path.join(teamDir, "config.json");
    this.config = this.loadConfig();
  }

  private loadConfig(): TeamConfig {
    if (fs.existsSync(this.configPath)) return JSON.parse(fs.readFileSync(this.configPath, "utf-8")) as TeamConfig;
    return { team_name: "default", members: [] };
  }

  private saveConfig(): void {
    fs.writeFileSync(this.configPath, JSON.stringify(this.config, null, 2), "utf-8");
  }

  private findMember(name: string): TeamMember | undefined {
    return this.config.members.find((m) => m.name === name);
  }

  spawn(name: string, role: string, prompt: string): string {
    let member = this.findMember(name);
    if (member) {
      if (!["idle", "shutdown"].includes(member.status)) return `Error: '${name}' is currently ${member.status}`;
      member.status = "working"; member.role = role;
    } else {
      member = { name, role, status: "working" };
      this.config.members.push(member);
    }
    this.saveConfig();
    const worker = new Worker(__filename, {
      workerData: { mode: "teammate", name, role, prompt, workdir: WORKDIR, teamDir: this.teamDir, inboxDir: INBOX_DIR, tasksDir: TASKS_DIR },
    });
    worker.on("exit", () => {
      const m = this.findMember(name);
      if (m && m.status === "working") { m.status = "idle"; this.saveConfig(); }
    });
    return `Spawned '${name}' (role: ${role})`;
  }

  listAll(): string {
    if (!this.config.members.length) return "No teammates.";
    this.config = this.loadConfig();
    return [`Team: ${this.config.team_name}`, ...this.config.members.map((m) => `  ${m.name} (${m.role}): ${m.status}`)].join("\n");
  }

  memberNames(): string[] { return this.config.members.map((m) => m.name); }
}

const TEAM = new TeammateManager(TEAM_DIR);

type ToolInput = Record<string, unknown>;

function runBash(command: string, cwd = WORKDIR): string {
  const dangerous = ["rm -rf /", "sudo", "shutdown", "reboot"];
  if (dangerous.some((d) => command.includes(d))) return "Error: Dangerous command blocked";
  const result = spawnSync("bash", ["-c", command], { cwd, timeout: 120000, encoding: "utf-8" });
  if (result.error?.message?.includes("ETIMEDOUT")) return "Error: Timeout (120s)";
  const out = ((result.stdout || "") + (result.stderr || "")).trim();
  return (out || "(no output)").slice(0, 50000);
}

function runRead(filePath: string, workdir = WORKDIR): string {
  try { return fs.readFileSync(path.resolve(workdir, filePath), "utf-8").slice(0, 50000); }
  catch (e) { return `Error: ${e}`; }
}

function runWrite(filePath: string, content: string, workdir = WORKDIR): string {
  try {
    const fp = path.resolve(workdir, filePath);
    fs.mkdirSync(path.dirname(fp), { recursive: true });
    fs.writeFileSync(fp, content, "utf-8");
    return `Wrote ${content.length} bytes`;
  } catch (e) { return `Error: ${e}`; }
}

function runEdit(filePath: string, oldText: string, newText: string, workdir = WORKDIR): string {
  try {
    const fp = path.resolve(workdir, filePath);
    const content = fs.readFileSync(fp, "utf-8");
    if (!content.includes(oldText)) return `Error: Text not found in ${filePath}`;
    fs.writeFileSync(fp, content.replace(oldText, newText), "utf-8");
    return `Edited ${filePath}`;
  } catch (e) { return `Error: ${e}`; }
}

function scanUnclaimedTasks(tasksDir: string): Record<string, unknown>[] {
  if (!fs.existsSync(tasksDir)) return [];
  return fs.readdirSync(tasksDir)
    .filter((f) => /^task_\d+\.json$/.test(f)).sort()
    .map((f) => JSON.parse(fs.readFileSync(path.join(tasksDir, f), "utf-8")) as Record<string, unknown>)
    .filter((t) => t.status === "pending" && !t.owner && !(t.blockedBy as unknown[])?.length);
}

function claimTask(tasksDir: string, taskId: number, owner: string): string {
  const p = path.join(tasksDir, `task_${taskId}.json`);
  if (!fs.existsSync(p)) return `Error: Task ${taskId} not found`;
  const task = JSON.parse(fs.readFileSync(p, "utf-8")) as Record<string, unknown>;
  task.owner = owner;
  task.status = "in_progress";
  fs.writeFileSync(p, JSON.stringify(task, null, 2), "utf-8");
  return `Claimed task #${taskId} for ${owner}`;
}

// -- Lead-specific protocol handlers --
function handleShutdownRequest(teammate: string): string {
  const reqId = randomUUID().slice(0, 8);
  shutdownRequests.set(reqId, { target: teammate, status: "pending" });
  BUS.send("lead", teammate, "Please shut down gracefully.", "shutdown_request", { request_id: reqId });
  return `Shutdown request ${reqId} sent to '${teammate}'`;
}

function handlePlanReview(requestId: string, approve: boolean, feedback = ""): string {
  const req = planRequests.get(requestId);
  if (!req) return `Error: Unknown plan request_id '${requestId}'`;
  req.status = approve ? "approved" : "rejected";
  BUS.send("lead", req.from, feedback, "plan_approval_response", { request_id: requestId, approve, feedback });
  return `Plan ${req.status} for '${req.from}'`;
}

const TOOL_HANDLERS: Record<string, (kw: ToolInput) => string> = {
  bash:              (kw) => runBash(kw.command as string),
  read_file:         (kw) => runRead(kw.path as string),
  write_file:        (kw) => runWrite(kw.path as string, kw.content as string),
  edit_file:         (kw) => runEdit(kw.path as string, kw.old_text as string, kw.new_text as string),
  spawn_teammate:    (kw) => TEAM.spawn(kw.name as string, kw.role as string, kw.prompt as string),
  list_teammates:    () => TEAM.listAll(),
  send_message:      (kw) => BUS.send("lead", kw.to as string, kw.content as string, (kw.msg_type as string) || "message"),
  read_inbox:        () => JSON.stringify(BUS.readInbox("lead"), null, 2),
  broadcast:         (kw) => BUS.broadcast("lead", kw.content as string, TEAM.memberNames()),
  shutdown_request:  (kw) => handleShutdownRequest(kw.teammate as string),
  shutdown_response: (kw) => JSON.stringify(shutdownRequests.get(kw.request_id as string) || { error: "not found" }),
  plan_approval:     (kw) => handlePlanReview(kw.request_id as string, kw.approve as boolean, kw.feedback as string),
  idle:              () => "Lead does not idle.",
  claim_task:        (kw) => claimTask(TASKS_DIR, kw.task_id as number, "lead"),
};

const TOOLS: Anthropic.Tool[] = [
  { name: "bash", description: "Run a shell command.", input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
  { name: "read_file", description: "Read file contents.", input_schema: { type: "object" as const, properties: { path: { type: "string" }, limit: { type: "integer" } }, required: ["path"] } },
  { name: "write_file", description: "Write content to file.", input_schema: { type: "object" as const, properties: { path: { type: "string" }, content: { type: "string" } }, required: ["path", "content"] } },
  { name: "edit_file", description: "Replace exact text in file.", input_schema: { type: "object" as const, properties: { path: { type: "string" }, old_text: { type: "string" }, new_text: { type: "string" } }, required: ["path", "old_text", "new_text"] } },
  { name: "spawn_teammate", description: "Spawn an autonomous teammate.", input_schema: { type: "object" as const, properties: { name: { type: "string" }, role: { type: "string" }, prompt: { type: "string" } }, required: ["name", "role", "prompt"] } },
  { name: "list_teammates", description: "List all teammates.", input_schema: { type: "object" as const, properties: {} } },
  { name: "send_message", description: "Send a message to a teammate.", input_schema: { type: "object" as const, properties: { to: { type: "string" }, content: { type: "string" }, msg_type: { type: "string", enum: [...VALID_MSG_TYPES] } }, required: ["to", "content"] } },
  { name: "read_inbox", description: "Read and drain the lead's inbox.", input_schema: { type: "object" as const, properties: {} } },
  { name: "broadcast", description: "Send a message to all teammates.", input_schema: { type: "object" as const, properties: { content: { type: "string" } }, required: ["content"] } },
  { name: "shutdown_request", description: "Request a teammate to shut down.", input_schema: { type: "object" as const, properties: { teammate: { type: "string" } }, required: ["teammate"] } },
  { name: "shutdown_response", description: "Check shutdown request status.", input_schema: { type: "object" as const, properties: { request_id: { type: "string" } }, required: ["request_id"] } },
  { name: "plan_approval", description: "Approve or reject a teammate's plan.", input_schema: { type: "object" as const, properties: { request_id: { type: "string" }, approve: { type: "boolean" }, feedback: { type: "string" } }, required: ["request_id", "approve"] } },
  { name: "idle", description: "Enter idle state (for lead -- rarely used).", input_schema: { type: "object" as const, properties: {} } },
  { name: "claim_task", description: "Claim a task from the board by ID.", input_schema: { type: "object" as const, properties: { task_id: { type: "integer" } }, required: ["task_id"] } },
];

// -- Worker thread: autonomous teammate --
if (!isMainThread) {
  const { mode, name, role, prompt, workdir, inboxDir, tasksDir } = workerData as {
    mode: string; name: string; role: string; prompt: string;
    workdir: string; teamDir: string; inboxDir: string; tasksDir: string;
  };

  if (mode === "teammate") {
    const client2 = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
    const model2 = process.env.MODEL_ID!;
    const bus = new MessageBus(inboxDir);
    const localPlanRequests: Map<string, Record<string, unknown>> = new Map();

    // Load team config to get team_name
    const configPath = path.join(path.dirname(inboxDir), "config.json");
    let teamName = "default";
    if (fs.existsSync(configPath)) {
      const cfg = JSON.parse(fs.readFileSync(configPath, "utf-8")) as { team_name?: string };
      teamName = cfg.team_name || "default";
    }

    function setStatus(status: string): void {
      if (!fs.existsSync(configPath)) return;
      const cfg = JSON.parse(fs.readFileSync(configPath, "utf-8")) as TeamConfig;
      const member = cfg.members.find((m) => m.name === name);
      if (member) { member.status = status; fs.writeFileSync(configPath, JSON.stringify(cfg, null, 2), "utf-8"); }
    }

    const sysPrompt = `You are '${name}', role: ${role}, team: ${teamName}, at ${workdir}. Use idle tool when you have no more work. You will auto-claim new tasks.`;
    const messages: Anthropic.MessageParam[] = [{ role: "user", content: prompt }];
    const tools: Anthropic.Tool[] = [
      { name: "bash", description: "Run a shell command.", input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
      { name: "read_file", description: "Read file contents.", input_schema: { type: "object" as const, properties: { path: { type: "string" } }, required: ["path"] } },
      { name: "write_file", description: "Write content to file.", input_schema: { type: "object" as const, properties: { path: { type: "string" }, content: { type: "string" } }, required: ["path", "content"] } },
      { name: "edit_file", description: "Replace exact text in file.", input_schema: { type: "object" as const, properties: { path: { type: "string" }, old_text: { type: "string" }, new_text: { type: "string" } }, required: ["path", "old_text", "new_text"] } },
      { name: "send_message", description: "Send message to a teammate.", input_schema: { type: "object" as const, properties: { to: { type: "string" }, content: { type: "string"}, msg_type: { type: "string", enum: [...VALID_MSG_TYPES] } }, required: ["to", "content"] } },
      { name: "read_inbox", description: "Read and drain your inbox.", input_schema: { type: "object" as const, properties: {} } },
      { name: "shutdown_response", description: "Respond to a shutdown request.", input_schema: { type: "object" as const, properties: { request_id: { type: "string" }, approve: { type: "boolean" }, reason: { type: "string" } }, required: ["request_id", "approve"] } },
      { name: "plan_approval", description: "Submit a plan for lead approval.", input_schema: { type: "object" as const, properties: { plan: { type: "string" } }, required: ["plan"] } },
      { name: "idle", description: "Signal that you have no more work. Enters idle polling phase.", input_schema: { type: "object" as const, properties: {} } },
      { name: "claim_task", description: "Claim a task from the task board by ID.", input_schema: { type: "object" as const, properties: { task_id: { type: "integer" } }, required: ["task_id"] } },
    ];

    const sleep = (ms: number) => new Promise<void>((resolve) => setTimeout(resolve, ms));

    (async () => {
      while (true) {
        // -- WORK PHASE --
        let idleRequested = false;
        for (let i = 0; i < 50; i++) {
          const inbox = bus.readInbox(name);
          for (const msg of inbox) {
            if ((msg.type as string) === "shutdown_request") { setStatus("shutdown"); parentPort?.postMessage({ status: "done" }); return; }
            messages.push({ role: "user", content: JSON.stringify(msg) });
          }
          let response: Anthropic.Message;
          try { response = await client2.messages.create({ model: model2, system: sysPrompt, messages, tools, max_tokens: 8000 }); }
          catch { setStatus("idle"); parentPort?.postMessage({ status: "done" }); return; }
          messages.push({ role: "assistant", content: response.content });
          if (response.stop_reason !== "tool_use") break;
          const results: Anthropic.ToolResultBlockParam[] = [];
          for (const block of response.content) {
            if (block.type === "tool_use") {
              const inp = block.input as ToolInput;
              let output: string;
              if (block.name === "idle") { idleRequested = true; output = "Entering idle phase. Will poll for new tasks."; }
              else if (block.name === "bash") output = runBash(inp.command as string, workdir);
              else if (block.name === "read_file") output = runRead(inp.path as string, workdir);
              else if (block.name === "write_file") output = runWrite(inp.path as string, inp.content as string, workdir);
              else if (block.name === "edit_file") output = runEdit(inp.path as string, inp.old_text as string, inp.new_text as string, workdir);
              else if (block.name === "send_message") output = bus.send(name, inp.to as string, inp.content as string, (inp.msg_type as string) || "message");
              else if (block.name === "read_inbox") output = JSON.stringify(bus.readInbox(name), null, 2);
              else if (block.name === "shutdown_response") {
                const approve = inp.approve as boolean;
                bus.send(name, "lead", (inp.reason as string) || "", "shutdown_response", { request_id: inp.request_id, approve });
                output = `Shutdown ${approve ? "approved" : "rejected"}`;
                if (approve) { setStatus("shutdown"); parentPort?.postMessage({ status: "done" }); return; }
              } else if (block.name === "plan_approval") {
                const planText = (inp.plan as string) || "";
                const reqId = randomUUID().slice(0, 8);
                localPlanRequests.set(reqId, { from: name, plan: planText, status: "pending" });
                bus.send(name, "lead", planText, "plan_approval_response", { request_id: reqId, plan: planText });
                output = `Plan submitted (request_id=${reqId}). Waiting for approval.`;
              } else if (block.name === "claim_task") {
                output = claimTask(tasksDir, inp.task_id as number, name);
              } else output = `Unknown tool: ${block.name}`;
              process.stdout.write(`  [${name}] ${block.name}: ${String(output).slice(0, 120)}\n`);
              results.push({ type: "tool_result", tool_use_id: block.id, content: String(output) });
            }
          }
          messages.push({ role: "user", content: results });
          if (idleRequested) break;
        }

        // -- IDLE PHASE: poll for inbox messages and unclaimed tasks --
        setStatus("idle");
        let resume = false;
        const polls = IDLE_TIMEOUT / POLL_INTERVAL;
        for (let p = 0; p < polls; p++) {
          await sleep(POLL_INTERVAL);
          const inbox = bus.readInbox(name);
          if (inbox.length) {
            for (const msg of inbox) {
              if ((msg.type as string) === "shutdown_request") { setStatus("shutdown"); parentPort?.postMessage({ status: "done" }); return; }
              messages.push({ role: "user", content: JSON.stringify(msg) });
            }
            resume = true; break;
          }
          const unclaimed = scanUnclaimedTasks(tasksDir);
          if (unclaimed.length) {
            const task = unclaimed[0];
            claimTask(tasksDir, task.id as number, name);
            if (messages.length <= 3) {
              messages.unshift({ role: "user", content: `<identity>You are '${name}', role: ${role}, team: ${teamName}. Continue your work.</identity>` });
              messages.splice(1, 0, { role: "assistant", content: `I am ${name}. Continuing.` });
            }
            messages.push({ role: "user", content: `<auto-claimed>Task #${task.id}: ${task.subject}\n${(task.description as string) || ""}</auto-claimed>` });
            messages.push({ role: "assistant", content: `Claimed task #${task.id}. Working on it.` });
            resume = true; break;
          }
        }
        if (!resume) { setStatus("shutdown"); parentPort?.postMessage({ status: "done" }); return; }
        setStatus("working");
      }
    })().catch(() => parentPort?.postMessage({ status: "error" }));
  }
}

// -- Main thread --
const client = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
const MODEL = process.env.MODEL_ID!;
const SYSTEM = `You are a team lead at ${WORKDIR}. Teammates are autonomous -- they find work themselves.`;

async function agentLoop(messages: Anthropic.MessageParam[]): Promise<void> {
  while (true) {
    const inbox = BUS.readInbox("lead");
    if (inbox.length) {
      messages.push({ role: "user", content: `<inbox>${JSON.stringify(inbox, null, 2)}</inbox>` });
      messages.push({ role: "assistant", content: "Noted inbox messages." });
    }
    const response = await client.messages.create({ model: MODEL, system: SYSTEM, messages, tools: TOOLS, max_tokens: 8000 });
    messages.push({ role: "assistant", content: response.content });
    if (response.stop_reason !== "tool_use") return;
    const results: Anthropic.ToolResultBlockParam[] = [];
    for (const block of response.content) {
      if (block.type === "tool_use") {
        const handler = TOOL_HANDLERS[block.name];
        let output: string;
        try { output = handler ? handler(block.input as ToolInput) : `Unknown tool: ${block.name}`; }
        catch (e) { output = `Error: ${e}`; }
        process.stdout.write(`> ${block.name}: ${String(output).slice(0, 200)}\n`);
        results.push({ type: "tool_result", tool_use_id: block.id, content: String(output) });
      }
    }
    messages.push({ role: "user", content: results });
  }
}

async function main() {
  if (!isMainThread) return;
  const history: Anthropic.MessageParam[] = [];
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
  const ask = () => new Promise<string>((resolve) => rl.question("\x1b[36ms11 >> \x1b[0m", resolve));

  while (true) {
    let query: string;
    try { query = await ask(); } catch { break; }
    if (["q", "exit", ""].includes(query.trim().toLowerCase())) break;
    if (query.trim() === "/team") { process.stdout.write(TEAM.listAll() + "\n"); continue; }
    if (query.trim() === "/inbox") { process.stdout.write(JSON.stringify(BUS.readInbox("lead"), null, 2) + "\n"); continue; }
    if (query.trim() === "/tasks") {
      if (fs.existsSync(TASKS_DIR)) {
        const files = fs.readdirSync(TASKS_DIR).filter((f) => /^task_\d+\.json$/.test(f)).sort();
        for (const f of files) {
          const t = JSON.parse(fs.readFileSync(path.join(TASKS_DIR, f), "utf-8")) as Record<string, unknown>;
          const markers: Record<string, string> = { pending: "[ ]", in_progress: "[>]", completed: "[x]" };
          const marker = markers[t.status as string] || "[?]";
          const owner = t.owner ? ` @${t.owner}` : "";
          process.stdout.write(`  ${marker} #${t.id}: ${t.subject}${owner}\n`);
        }
      }
      continue;
    }
    history.push({ role: "user", content: query });
    await agentLoop(history);
    const last = history[history.length - 1];
    if (last.role === "assistant" && Array.isArray(last.content)) {
      for (const block of last.content) {
        if (block.type === "text") process.stdout.write(block.text + "\n");
      }
    }
    process.stdout.write("\n");
  }
  rl.close();
}

main().catch(console.error);

#!/usr/bin/env tsx
/**
 * s12_worktree_task_isolation.ts - Worktree + Task Isolation
 *
 * Directory-level isolation for parallel task execution.
 * Tasks are the control plane and worktrees are the execution plane.
 *
 *     .tasks/task_12.json
 *       {
 *         "id": 12,
 *         "subject": "Implement auth refactor",
 *         "status": "in_progress",
 *         "worktree": "auth-refactor"
 *       }
 *
 *     .worktrees/index.json
 *       {
 *         "worktrees": [
 *           {
 *             "name": "auth-refactor",
 *             "path": ".../.worktrees/auth-refactor",
 *             "branch": "wt/auth-refactor",
 *             "task_id": 12,
 *             "status": "active"
 *           }
 *         ]
 *       }
 *
 * Key insight: "Isolate by directory, coordinate by task ID."
 */

import Anthropic from "@anthropic-ai/sdk";
import * as dotenv from "dotenv";
import { spawnSync } from "child_process";
import * as fs from "fs";
import * as path from "path";
import * as readline from "readline";

dotenv.config({ override: true });

const client = new Anthropic({ baseURL: process.env.ANTHROPIC_BASE_URL });
const MODEL = process.env.MODEL_ID!;
const WORKDIR = process.cwd();

function detectRepoRoot(cwd: string): string | null {
  try {
    const result = spawnSync("git", ["rev-parse", "--show-toplevel"], {
      cwd, timeout: 10000, encoding: "utf-8",
    });
    if (result.status !== 0) return null;
    const root = result.stdout.trim();
    return fs.existsSync(root) ? root : null;
  } catch { return null; }
}

const REPO_ROOT = detectRepoRoot(WORKDIR) || WORKDIR;

const SYSTEM = `You are a coding agent at ${WORKDIR}. Use task + worktree tools for multi-task work. For parallel or risky changes: create tasks, allocate worktree lanes, run commands in those lanes, then choose keep/remove for closeout. Use worktree_events when you need lifecycle visibility.`;

// -- EventBus: append-only lifecycle events for observability --
class EventBus {
  constructor(private eventLogPath: string) {
    fs.mkdirSync(path.dirname(eventLogPath), { recursive: true });
    if (!fs.existsSync(eventLogPath)) fs.writeFileSync(eventLogPath, "", "utf-8");
  }

  emit(event: string, task: Record<string, unknown> = {}, worktree: Record<string, unknown> = {}, error?: string): void {
    const payload: Record<string, unknown> = { event, ts: Date.now() / 1000, task, worktree };
    if (error) payload.error = error;
    fs.appendFileSync(this.eventLogPath, JSON.stringify(payload) + "\n", "utf-8");
  }

  listRecent(limit = 20): string {
    const n = Math.max(1, Math.min(Math.floor(limit || 20), 200));
    const lines = fs.readFileSync(this.eventLogPath, "utf-8").split("\n").filter(Boolean);
    const recent = lines.slice(-n);
    const items = recent.map((line) => { try { return JSON.parse(line) as unknown; } catch { return { event: "parse_error", raw: line }; } });
    return JSON.stringify(items, null, 2);
  }
}

interface Task {
  id: number; subject: string; description: string;
  status: "pending" | "in_progress" | "completed";
  owner: string; worktree: string; blockedBy: number[];
  created_at: number; updated_at: number;
}

// -- TaskManager: persistent task board with optional worktree binding --
class TaskManager {
  private nextId: number;

  constructor(private tasksDir: string) {
    fs.mkdirSync(tasksDir, { recursive: true });
    this.nextId = this.maxId() + 1;
  }

  private maxId(): number {
    const ids = fs.readdirSync(this.tasksDir)
      .filter((f) => /^task_\d+\.json$/.test(f))
      .map((f) => parseInt(f.split("_")[1]));
    return ids.length ? Math.max(...ids) : 0;
  }

  private taskPath(id: number): string { return path.join(this.tasksDir, `task_${id}.json`); }

  private load(id: number): Task {
    const p = this.taskPath(id);
    if (!fs.existsSync(p)) throw new Error(`Task ${id} not found`);
    return JSON.parse(fs.readFileSync(p, "utf-8")) as Task;
  }

  private save(task: Task): void { fs.writeFileSync(this.taskPath(task.id), JSON.stringify(task, null, 2), "utf-8"); }

  exists(id: number): boolean { return fs.existsSync(this.taskPath(id)); }

  create(subject: string, description = ""): string {
    const now = Date.now() / 1000;
    const task: Task = { id: this.nextId, subject, description, status: "pending", owner: "", worktree: "", blockedBy: [], created_at: now, updated_at: now };
    this.save(task); this.nextId++;
    return JSON.stringify(task, null, 2);
  }

  get(id: number): string { return JSON.stringify(this.load(id), null, 2); }

  update(id: number, status?: string, owner?: string): string {
    const task = this.load(id);
    if (status) {
      if (!["pending", "in_progress", "completed"].includes(status)) throw new Error(`Invalid status: ${status}`);
      task.status = status as Task["status"];
    }
    if (owner !== undefined) task.owner = owner;
    task.updated_at = Date.now() / 1000;
    this.save(task);
    return JSON.stringify(task, null, 2);
  }

  bindWorktree(id: number, worktree: string, owner = ""): string {
    const task = this.load(id);
    task.worktree = worktree;
    if (owner) task.owner = owner;
    if (task.status === "pending") task.status = "in_progress";
    task.updated_at = Date.now() / 1000;
    this.save(task);
    return JSON.stringify(task, null, 2);
  }

  unbindWorktree(id: number): string {
    const task = this.load(id);
    task.worktree = ""; task.updated_at = Date.now() / 1000;
    this.save(task);
    return JSON.stringify(task, null, 2);
  }

  listAll(): string {
    const files = fs.readdirSync(this.tasksDir).filter((f) => /^task_\d+\.json$/.test(f)).sort();
    if (!files.length) return "No tasks.";
    const markers: Record<string, string> = { pending: "[ ]", in_progress: "[>]", completed: "[x]" };
    return files.map((f) => {
      const t = JSON.parse(fs.readFileSync(path.join(this.tasksDir, f), "utf-8")) as Task;
      const marker = markers[t.status] || "[?]";
      const owner = t.owner ? ` owner=${t.owner}` : "";
      const wt = t.worktree ? ` wt=${t.worktree}` : "";
      return `${marker} #${t.id}: ${t.subject}${owner}${wt}`;
    }).join("\n");
  }
}

const TASKS = new TaskManager(path.join(REPO_ROOT, ".tasks"));
const EVENTS = new EventBus(path.join(REPO_ROOT, ".worktrees", "events.jsonl"));

interface WorktreeEntry {
  name: string; path: string; branch: string;
  task_id: number | null; status: string; created_at: number;
  removed_at?: number; kept_at?: number;
}

interface WorktreeIndex { worktrees: WorktreeEntry[]; }

// -- WorktreeManager: create/list/run/remove git worktrees + lifecycle index --
class WorktreeManager {
  private indexPath: string;
  public gitAvailable: boolean;

  constructor(private repoRoot: string, private tasks: TaskManager, private events: EventBus) {
    const wtDir = path.join(repoRoot, ".worktrees");
    fs.mkdirSync(wtDir, { recursive: true });
    this.indexPath = path.join(wtDir, "index.json");
    if (!fs.existsSync(this.indexPath)) fs.writeFileSync(this.indexPath, JSON.stringify({ worktrees: [] }, null, 2), "utf-8");
    this.gitAvailable = this.isGitRepo();
  }

  private isGitRepo(): boolean {
    try {
      const r = spawnSync("git", ["rev-parse", "--is-inside-work-tree"], { cwd: this.repoRoot, timeout: 10000, encoding: "utf-8" });
      return r.status === 0;
    } catch { return false; }
  }

  private runGit(args: string[]): string {
    if (!this.gitAvailable) throw new Error("Not in a git repository. worktree tools require git.");
    const r = spawnSync("git", args, { cwd: this.repoRoot, timeout: 120000, encoding: "utf-8" });
    if (r.status !== 0) { const msg = ((r.stdout || "") + (r.stderr || "")).trim(); throw new Error(msg || `git ${args.join(" ")} failed`); }
    return ((r.stdout || "") + (r.stderr || "")).trim() || "(no output)";
  }

  private loadIndex(): WorktreeIndex { return JSON.parse(fs.readFileSync(this.indexPath, "utf-8")) as WorktreeIndex; }
  private saveIndex(data: WorktreeIndex): void { fs.writeFileSync(this.indexPath, JSON.stringify(data, null, 2), "utf-8"); }
  private find(name: string): WorktreeEntry | undefined { return this.loadIndex().worktrees.find((w) => w.name === name); }

  private validateName(name: string): void {
    if (!/^[A-Za-z0-9._-]{1,40}$/.test(name || "")) throw new Error("Invalid worktree name. Use 1-40 chars: letters, numbers, ., _, -");
  }

  create(name: string, taskId?: number, baseRef = "HEAD"): string {
    this.validateName(name);
    if (this.find(name)) throw new Error(`Worktree '${name}' already exists in index`);
    if (taskId !== undefined && !this.tasks.exists(taskId)) throw new Error(`Task ${taskId} not found`);

    const wtPath = path.join(this.repoRoot, ".worktrees", name);
    const branch = `wt/${name}`;
    this.events.emit("worktree.create.before", taskId !== undefined ? { id: taskId } : {}, { name, base_ref: baseRef });
    try {
      this.runGit(["worktree", "add", "-b", branch, wtPath, baseRef]);
      const entry: WorktreeEntry = { name, path: wtPath, branch, task_id: taskId ?? null, status: "active", created_at: Date.now() / 1000 };
      const idx = this.loadIndex();
      idx.worktrees.push(entry);
      this.saveIndex(idx);
      if (taskId !== undefined) this.tasks.bindWorktree(taskId, name);
      this.events.emit("worktree.create.after", taskId !== undefined ? { id: taskId } : {}, { name, path: wtPath, branch, status: "active" });
      return JSON.stringify(entry, null, 2);
    } catch (e) {
      this.events.emit("worktree.create.failed", taskId !== undefined ? { id: taskId } : {}, { name, base_ref: baseRef }, String(e));
      throw e;
    }
  }

  listAll(): string {
    const wts = this.loadIndex().worktrees;
    if (!wts.length) return "No worktrees in index.";
    return wts.map((wt) => {
      const suffix = wt.task_id !== null ? ` task=${wt.task_id}` : "";
      return `[${wt.status || "unknown"}] ${wt.name} -> ${wt.path} (${wt.branch || "-"})${suffix}`;
    }).join("\n");
  }

  status(name: string): string {
    const wt = this.find(name);
    if (!wt) return `Error: Unknown worktree '${name}'`;
    if (!fs.existsSync(wt.path)) return `Error: Worktree path missing: ${wt.path}`;
    const r = spawnSync("git", ["status", "--short", "--branch"], { cwd: wt.path, timeout: 60000, encoding: "utf-8" });
    return ((r.stdout || "") + (r.stderr || "")).trim() || "Clean worktree";
  }

  run(name: string, command: string): string {
    const dangerous = ["rm -rf /", "sudo", "shutdown", "reboot", "> /dev/"];
    if (dangerous.some((d) => command.includes(d))) return "Error: Dangerous command blocked";
    const wt = this.find(name);
    if (!wt) return `Error: Unknown worktree '${name}'`;
    if (!fs.existsSync(wt.path)) return `Error: Worktree path missing: ${wt.path}`;
    const r = spawnSync("bash", ["-c", command], { cwd: wt.path, timeout: 300000, encoding: "utf-8" });
    const out = ((r.stdout || "") + (r.stderr || "")).trim();
    return (out || "(no output)").slice(0, 50000);
  }

  remove(name: string, force = false, completeTask = false): string {
    const wt = this.find(name);
    if (!wt) return `Error: Unknown worktree '${name}'`;
    this.events.emit("worktree.remove.before", wt.task_id !== null ? { id: wt.task_id } : {}, { name, path: wt.path });
    try {
      const args = ["worktree", "remove"];
      if (force) args.push("--force");
      args.push(wt.path);
      this.runGit(args);
      if (completeTask && wt.task_id !== null) {
        const before = JSON.parse(this.tasks.get(wt.task_id)) as Task;
        this.tasks.update(wt.task_id, "completed");
        this.tasks.unbindWorktree(wt.task_id);
        this.events.emit("task.completed", { id: wt.task_id, subject: before.subject, status: "completed" }, { name });
      }
      const idx = this.loadIndex();
      for (const item of idx.worktrees) {
        if (item.name === name) { item.status = "removed"; item.removed_at = Date.now() / 1000; }
      }
      this.saveIndex(idx);
      this.events.emit("worktree.remove.after", wt.task_id !== null ? { id: wt.task_id } : {}, { name, path: wt.path, status: "removed" });
      return `Removed worktree '${name}'`;
    } catch (e) {
      this.events.emit("worktree.remove.failed", wt.task_id !== null ? { id: wt.task_id } : {}, { name, path: wt.path }, String(e));
      throw e;
    }
  }

  keep(name: string): string {
    const wt = this.find(name);
    if (!wt) return `Error: Unknown worktree '${name}'`;
    const idx = this.loadIndex();
    let kept: WorktreeEntry | undefined;
    for (const item of idx.worktrees) {
      if (item.name === name) { item.status = "kept"; item.kept_at = Date.now() / 1000; kept = item; }
    }
    this.saveIndex(idx);
    this.events.emit("worktree.keep", wt.task_id !== null ? { id: wt.task_id } : {}, { name, path: wt.path, status: "kept" });
    return kept ? JSON.stringify(kept, null, 2) : `Error: Unknown worktree '${name}'`;
  }
}

const WORKTREES = new WorktreeManager(REPO_ROOT, TASKS, EVENTS);

type ToolInput = Record<string, unknown>;

function safePath(p: string): string {
  const resolved = path.resolve(WORKDIR, p);
  if (!resolved.startsWith(WORKDIR)) throw new Error(`Path escapes workspace: ${p}`);
  return resolved;
}

function runBash(command: string): string {
  const dangerous = ["rm -rf /", "sudo", "shutdown", "reboot", "> /dev/"];
  if (dangerous.some((d) => command.includes(d))) return "Error: Dangerous command blocked";
  const result = spawnSync("bash", ["-c", command], { cwd: WORKDIR, timeout: 120000, encoding: "utf-8" });
  if (result.error?.message?.includes("ETIMEDOUT")) return "Error: Timeout (120s)";
  const out = ((result.stdout || "") + (result.stderr || "")).trim();
  return (out || "(no output)").slice(0, 50000);
}

function runRead(filePath: string, limit?: number): string {
  try {
    const lines = fs.readFileSync(safePath(filePath), "utf-8").split("\n");
    const limited = (limit && limit < lines.length) ? [...lines.slice(0, limit), `... (${lines.length - limit} more)`] : lines;
    return limited.join("\n").slice(0, 50000);
  } catch (e) { return `Error: ${e}`; }
}

function runWrite(filePath: string, content: string): string {
  try {
    const fp = safePath(filePath);
    fs.mkdirSync(path.dirname(fp), { recursive: true });
    fs.writeFileSync(fp, content, "utf-8");
    return `Wrote ${content.length} bytes`;
  } catch (e) { return `Error: ${e}`; }
}

function runEdit(filePath: string, oldText: string, newText: string): string {
  try {
    const fp = safePath(filePath);
    const content = fs.readFileSync(fp, "utf-8");
    if (!content.includes(oldText)) return `Error: Text not found in ${filePath}`;
    fs.writeFileSync(fp, content.replace(oldText, newText), "utf-8");
    return `Edited ${filePath}`;
  } catch (e) { return `Error: ${e}`; }
}

const TOOL_HANDLERS: Record<string, (kw: ToolInput) => string> = {
  bash:               (kw) => runBash(kw.command as string),
  read_file:          (kw) => runRead(kw.path as string, kw.limit as number | undefined),
  write_file:         (kw) => runWrite(kw.path as string, kw.content as string),
  edit_file:          (kw) => runEdit(kw.path as string, kw.old_text as string, kw.new_text as string),
  task_create:        (kw) => TASKS.create(kw.subject as string, kw.description as string | undefined),
  task_list:          () => TASKS.listAll(),
  task_get:           (kw) => TASKS.get(kw.task_id as number),
  task_update:        (kw) => TASKS.update(kw.task_id as number, kw.status as string | undefined, kw.owner as string | undefined),
  task_bind_worktree: (kw) => TASKS.bindWorktree(kw.task_id as number, kw.worktree as string, kw.owner as string | undefined),
  worktree_create:    (kw) => WORKTREES.create(kw.name as string, kw.task_id as number | undefined, kw.base_ref as string | undefined),
  worktree_list:      () => WORKTREES.listAll(),
  worktree_status:    (kw) => WORKTREES.status(kw.name as string),
  worktree_run:       (kw) => WORKTREES.run(kw.name as string, kw.command as string),
  worktree_keep:      (kw) => WORKTREES.keep(kw.name as string),
  worktree_remove:    (kw) => WORKTREES.remove(kw.name as string, kw.force as boolean | undefined, kw.complete_task as boolean | undefined),
  worktree_events:    (kw) => EVENTS.listRecent(kw.limit as number | undefined),
};

const TOOLS: Anthropic.Tool[] = [
  { name: "bash", description: "Run a shell command in the current workspace (blocking).", input_schema: { type: "object" as const, properties: { command: { type: "string" } }, required: ["command"] } },
  { name: "read_file", description: "Read file contents.", input_schema: { type: "object" as const, properties: { path: { type: "string" }, limit: { type: "integer" } }, required: ["path"] } },
  { name: "write_file", description: "Write content to file.", input_schema: { type: "object" as const, properties: { path: { type: "string" }, content: { type: "string" } }, required: ["path", "content"] } },
  { name: "edit_file", description: "Replace exact text in file.", input_schema: { type: "object" as const, properties: { path: { type: "string" }, old_text: { type: "string" }, new_text: { type: "string" } }, required: ["path", "old_text", "new_text"] } },
  { name: "task_create", description: "Create a new task on the shared task board.", input_schema: { type: "object" as const, properties: { subject: { type: "string" }, description: { type: "string" } }, required: ["subject"] } },
  { name: "task_list", description: "List all tasks with status, owner, and worktree binding.", input_schema: { type: "object" as const, properties: {} } },
  { name: "task_get", description: "Get task details by ID.", input_schema: { type: "object" as const, properties: { task_id: { type: "integer" } }, required: ["task_id"] } },
  { name: "task_update", description: "Update task status or owner.", input_schema: { type: "object" as const, properties: { task_id: { type: "integer" }, status: { type: "string", enum: ["pending", "in_progress", "completed"] }, owner: { type: "string" } }, required: ["task_id"] } },
  { name: "task_bind_worktree", description: "Bind a task to a worktree name.", input_schema: { type: "object" as const, properties: { task_id: { type: "integer" }, worktree: { type: "string" }, owner: { type: "string" } }, required: ["task_id", "worktree"] } },
  { name: "worktree_create", description: "Create a git worktree and optionally bind it to a task.", input_schema: { type: "object" as const, properties: { name: { type: "string" }, task_id: { type: "integer" }, base_ref: { type: "string" } }, required: ["name"] } },
  { name: "worktree_list", description: "List worktrees tracked in .worktrees/index.json.", input_schema: { type: "object" as const, properties: {} } },
  { name: "worktree_status", description: "Show git status for one worktree.", input_schema: { type: "object" as const, properties: { name: { type: "string" } }, required: ["name"] } },
  { name: "worktree_run", description: "Run a shell command in a named worktree directory.", input_schema: { type: "object" as const, properties: { name: { type: "string" }, command: { type: "string" } }, required: ["name", "command"] } },
  { name: "worktree_remove", description: "Remove a worktree and optionally mark its bound task completed.", input_schema: { type: "object" as const, properties: { name: { type: "string" }, force: { type: "boolean" }, complete_task: { type: "boolean" } }, required: ["name"] } },
  { name: "worktree_keep", description: "Mark a worktree as kept in lifecycle state without removing it.", input_schema: { type: "object" as const, properties: { name: { type: "string" } }, required: ["name"] } },
  { name: "worktree_events", description: "List recent worktree/task lifecycle events from .worktrees/events.jsonl.", input_schema: { type: "object" as const, properties: { limit: { type: "integer" } } } },
];

async function agentLoop(messages: Anthropic.MessageParam[]): Promise<void> {
  while (true) {
    const response = await client.messages.create({ model: MODEL, system: SYSTEM, messages, tools: TOOLS, max_tokens: 8000 });
    messages.push({ role: "assistant", content: response.content });
    if (response.stop_reason !== "tool_use") return;
    const results: Anthropic.ToolResultBlockParam[] = [];
    for (const block of response.content) {
      if (block.type === "tool_use") {
        const handler = TOOL_HANDLERS[block.name];
        let output: string;
        try { output = handler ? handler(block.input as ToolInput) : `Unknown tool: ${block.name}`; }
        catch (e) { output = `Error: ${e}`; }
        process.stdout.write(`> ${block.name}: ${String(output).slice(0, 200)}\n`);
        results.push({ type: "tool_result", tool_use_id: block.id, content: String(output) });
      }
    }
    messages.push({ role: "user", content: results });
  }
}

async function main() {
  process.stdout.write(`Repo root for s12: ${REPO_ROOT}\n`);
  if (!WORKTREES.gitAvailable) process.stdout.write("Note: Not in a git repo. worktree_* tools will return errors.\n");

  const history: Anthropic.MessageParam[] = [];
  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
  const ask = () => new Promise<string>((resolve) => rl.question("\x1b[36ms12 >> \x1b[0m", resolve));

  while (true) {
    let query: string;
    try { query = await ask(); } catch { break; }
    if (["q", "exit", ""].includes(query.trim().toLowerCase())) break;
    history.push({ role: "user", content: query });
    await agentLoop(history);
    const last = history[history.length - 1];
    if (last.role === "assistant" && Array.isArray(last.content)) {
      for (const block of last.content) {
        if (block.type === "text") process.stdout.write(block.text + "\n");
      }
    }
    process.stdout.write("\n");
  }
  rl.close();
}

main().catch(console.error);
